INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1171323','Цілого світа','Слова: о. Й. Кишакевич','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Цілого світа, сильний покрове,
Цілого світа, вічна надія,
Ласк милосердя, скарби любове,   |
Одна над нами Мати Маріє.        | (2)

В горю недолі до Тебе йдемо,
Помочі, ласки ніґде не маєм,
В молитві, пісні просьби несемо: |
Змилуйся над нами, Тебе благаєм. | (2)

Не дай пропасти і загибати
В сіти, що ворог її готовить,
Сиріт нещасних, всеблага Мати,   |
Наша надіє і наш покров.         | (2)

А наше серце не перестане
Тебе у піснях, мольбах славити,
Як довго світить небо зоряне,    |
Як довго серце буде в нас бити.  | (2)','["pisni.org.ua", "cat:do-bohorodyci", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1171323'), datetime('now')),datetime('now'));
