INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_117101','Тадж-Махал','Музика: Гурт "Океан Ельзи" Слова: Святослав Вакарчук','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Мене питають, коли поїду,
Всi питають, куди поїду
Лiтом я.
Усi знайомi i незнайомi,
Усi сусiди в моєму домi,
Вся сiм`я.
А я не знаю, та я не знаю -
Навiть часу не вистачає
На вiкенд.
I знов, i знов собi уявляю,
Як у iндiю я лiтаю -
В дивний Ленд...

Приспів:

Тадж-Махал, Тадж-Махал -
Ти iндiйский п`єдестал,
Схiдна стеля i пiдвал,
[Бiлый камень и метал]
A
О`є, Тадж-Махал!

Вiн там, де джунглi лiтають всюди,
Ходять пiшки до нього люди
На поклон.
Його побачити хочуть дуже,
Всiм показує шлях туди
Iндiйський слон.
Коли я буду у мiстi Делi,
[Субенюсь я у гатели]
Або нi...
Поїду я все одно до тебе,
Знай, читати знаки
На стiнi.

Приспів.','["pisni.org.ua", "cat:manrivni", "Пісні на мандрівну тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_117101'), datetime('now')),datetime('now'));
