INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1173426','Зачекай, моє дитинство','Музика: Наталія Май Слова: Наталія Май. Виконує: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Дитинство наше радісним було
Та раптом відзвеніло й відцвіло,
Злетіло тихо в сині небеса
І, мабуть, не повернеться назад.

Приспів:
Зачекай, моє дитинство! Зачекай!
Не спіши летіти у далекий край!
Наче птаха, білі крилоньки згорни, |
Щоб по довше ми лишалися дітьми!   | (2)

А я кричу дитинству: "Зупинись!"
А я його благаю: "Повернись!"
Воно сміється лагідно мені:
Я повернусь до тебе уві сні...

Приспів.

Все далі в небі зірка осяйна,
Мені завжди світитиме вона,
Від лиха берегтиме у житті,
Освятить всі дороги і путі.

Приспів. (2)','["pisni.org.ua", "cat:nostalgia", "Пісні з ностальгічними мотивами"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1173426'), datetime('now')),datetime('now'));
