INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1175202','Гори мої, гори','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Антологія лемківської пісні, Львів, "Афіша", 2005, с.129','Виконує: Іван Майчик, с.Одрехова','1. Гори мої, гори,
Ви зелені бори,
Та я ту виросла,
Як квіточка в поли.

2. Як квіточка в поли,
Зелений барвінок,
Сплітайте, дівчата,
Мі зелений вінок.

3. Співайте, дівчата,
Співайте весело,
Жеби ся молодій
Господарство вело.

4. Співайте, дівчата,
І я буду з вами,
Жеби нам горіла
Травка під ногами.

5. Як я си заспівам,
Далеко мя чути,
Аж до миленького,
Де я маю бути','["pisni.org.ua", "cat:lemkivski", "Лемківські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1175202'), datetime('now')),datetime('now'));
