INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_117404','Вітре цигане','Музика: Сергій Фоменко Слова: Сергій Фоменко. Виконує: Мандри','uk','ukraine_1991',NULL,NULL,'Записано на слух','Відео кліп — http://www.mandrymusic.com/video/Mandry_klip_Vitre.avi Тональність: Gm. Бій доволі легко підібрати на слух. Наприклад, в приспіві непогано звучить такий варіант: Чергування ударів згори вниз без глушіння та з глушінням струн: e|-x-3-x-3-x- b|-x-3-x-3-x- g|-x-3-x-3-x- d|-x-5-x-5-x- a|-x-5-x-5-x- e|-x-3-x-3-x-','Gm
Вітре цигане кличуть в дорогу
Гори високі, далекі краї.
Gm
Трави у росах, місяць і зорі
Вогнища ночі й думи сумні.
Вітре цигане в високім небі
Хмари далекі й лелеки...

Приспів:
Ай я й я я яй
Кохання ллється через край.
Ай я й я я яй
Кохання ллється через край.

Вітре цигане в полумї вогнищ
Сірі тумани, літа і дощі.
Даймони темряви й янголи божі
Мрії дитинства й казкові пісні.
Вітре, цигане, в високім небі
Хмари далекі й лелеки...

Тут звідкись узявся вар''ят-меестрель
Вискочив наче Пилип з конопель.
Ярий поспати всю ніч не давав
В неї під вікнами пісні співав:
Ніжно, чарівно, Ярино моя,
Хочу з тобою кохатися я.
Серце у грудях страждає й горить
На крилах до тебе литить.

Приспів.

Вітре цигане брате і пане
Чарівним дивом повіяла ніч.
У моїм серці загоїла рани
Світлом кохання радісна мить.
Вітре цигане в високім небі
Хмари далекі й лелеки...

Приспів.','["pisni.org.ua", "cat:krasa-pryrody", "cat:manrivni", "Пісні про красу природи", "Пісні на мандрівну тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_117404'), datetime('now')),datetime('now'));
