INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1175505','В Царіграді на базарі','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Книга:Українські народні пісні;В 2 книгах;Київ,"Мистецтво"1955;Кн1,стр.28-29',NULL,'В Царіграді на базарі,*(2)
Де брат сестру запродає,
Та не знає, що взять має;
Вона собі ціну знає:
"Бери гроші, не лічачи,
Сребро-злато, не важачи.
Сребро-злато, не важачи,
Китаєчку, не мірячи".
Десь узявся злий татарин,
Десь узявся презлий панич,
Дає гроші, не лічачи,
Китаєчку, не мірячи.
Став брат сестру з рук здавати,
Татарина научати:
"Татарине, презлий пане,
Не дай дівці заплакати,
Отця-неньку спом''янути,
В свою землю поглянути".
Дівка-бранка не втерпіла,
В свою землю поглянула.
В свою землю поглянула,
Отця-неньку спом''янула.
Як угледів злий татарин,
Як угледів презлий панич,
Та вдарився об білу грудь.
Десь узялась на морі хвиля,
Всі кораблики побила.
Всі кораблики побила,
Татарина затопила.
Татарина затопила,
Невольничку зоставила.
Невольничку зоставила,
В свою землю викинула.
Отця-неньку спом''янула,
В свою землю жить попала.

* - кожний рядок співається двічі','["pisni.org.ua", "cat:istorychni", "Історичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1175505'), datetime('now')),datetime('now'));
