INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1175220','Бувайте здорові','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Антологія лемківської пісні, Львів, "Афіша", 2005, с.135','Виконує: Магдалина Байко, с.Яблониця','1. Бувайте здорові, дорогі пороги, (2)
Що по вас ходили, що по вас ходили
Мої білі ноги.

2. Бувайте здорові і мої віконця, (2)
Що я вас вмивала, що я вас вмивала
Перед сходом сонця.

3. Бувайте здорові, ви, мої образи, (2)
Щом вас приберала, щом вас приберала
Тими рушниками.

4. Бувайте здорові і столи, і лави, (2)
Що я вас вкривала, що я вас вкривала
Тими обрусами.

5. Бувай же здорова ти, моя мамуню, (2)
Що добре ховала, що мя виховала
Та свою дівуню','["pisni.org.ua", "cat:lemkivski", "cat:vesilni", "Лемківські пісні", "Весільні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1175220'), datetime('now')),datetime('now'));
