INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_117707','В цьому Дворку як у Вінку!','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Колядка стародавня: Українське Різдво Світа. Рай розвився Господь звеселився. Сад садили Сад поливали. А в тій Хаті як у Раю В цьому Дворку як у Вінку В цьому Домі як у Раю Красная Панна Сад садила РОЗСПІВ: В цьо-му Двор-ку я-ак у-у Він-ку Щед-ри-ий Ве-чі-ір Доб-ри-ий Ве-чір ВИСЛОВЛЮВАННЯ: М. Грушевський: Єдиний наш духовний устрій. Щоб пізнати останки старої творчости, зв''язані з українським духовно-обрядовим кругом, найкраще пройти самим тим кругом, крок за кроком, пізнаючи останки старого світогляду. Річний круг — це заразом властиво єдиний наш духовний, обрядово-релігійний устрій, який заховує якусь світоглядну цілість, передчасно розбиту і зруйновану новими церковними, царськими та комуністичними заходами. На жаль тільки, ми й цього нашого старого річного круга не маємо в його повному і чистому передхристиянському вигляді і мусимо рахуватись на кожнім кроці не тільки з спустошеннями і виломами, але і з змінами, перебоями і переносами, спричиненими в старому устрої церквою і церковним календарем. Гострі заборони, напади, погрози, котрими духовенство било по святах, які не встигли себе зв''язати в той чи інший спосіб з святами християнськими, поставити свої останки під їх "протекторат" або асимілюватися з ними, — факт загально відомий. Від "Слова о казнех божих" до Івана Вишенського, і відти до ще новіших консисторських наказів маємо безконечний ланцюг цих церковних, єрархічних уїдань на народні свята взагалі, і особливо на ті, які носили на собі особливо яскраві прикмети українського світогляду і зв''язані були з свобідним паруванням молодіжи. Настільки ця війна була успішна, що тепер ми тільки й можемо зміркувати, які великі прогалини поробила тут церква, знищивши одно, друге покривши і замінивши християнськими обрядами, третє звівши на чисті посмішки й пародії. Ті "русалії", про котрі говорить згадане "Слово", великоднє "волочильне", "праздник діавольский на поле ісшедших з танцями і скоками" на св. Юрія, на котрі вдаряв Іван Вишенський, ті вінці, що "робились о клячінні та вночи на воду до річки носились" ("Супліка на попа"), переважно позникали так, що ледве зістався від них який слід. А що лишилося від величних весняних і купальських забав? (За книгою: Михайло Грушевський. Історія української літератури. Т. 1) Листки з приводу цієї Пісні: Колядки як Українські релігійні роздуми про Бога. Українське Свято Воведення 4.12 - Передріздвяний Святочний час. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Бог, Різдво Світа, Дідух і Лицарі. Співаймо Світові-Дитині: Колядки, Щедрівки, Колискові... Порівняння: Українці й Уралалтайці. Стежки до листків про Українські традиції.','В цьому Дворку як у Вінку!
Приспів: Щедрий Вечір Добрий Вечір!

Там Господар як Виноград
Там Господиня як Калина
Його сини як Соколи
Її Дочки  як Панночки

По Саду xодили Сад садили
Сад садили Сад поливали
Вищий Мене кращий Мене(1)','["pisni.org.ua", "cat:kolyadky", "cat:shchedrivky", "Колядки", "Щедрівки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_117707'), datetime('now')),datetime('now'));
