INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_118323','Не треба класти руку на плече','(Довіра). Музика: Ігор Косик Слова: Ліна Костенко. Виконує: Ігор Косик','uk','ukraine_1991',NULL,NULL,'http://pysar.tripod.com/Kostenko/Kostenko29.html','Підбір акордів: невідомий','Не треба класти руку на плече.
Цей рух доречний, може, тільки в танці.
Довіра — звір полоханий, втече.          |
Він любить тиху паморозь дистанцій.      | (2)

Він любить час. Хвилини. Дні. Роки.
Він дивний звір, він любить навіть муку. |
Він любить навіть відстань і розлуку.    | (2)
Але не любить на плечі руки.

У цих садах, в сонатах солов''їв,
Він чує тихі кроки браконьєра.
Він пастки жде від погляду, від слів,    |
І цей спектакль йому вже не прем''єра.    | (2)

Душі людської туго і тайго!
Це гарний звір, без нього зле живеться.
Але не треба кликати його.               |
Він прийде сам і вже не відсахнеться.    | (2)','["pisni.org.ua", "cat:bardivski", "cat:druzhba", "Бардівські пісні", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_118323'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_118323','Не треба класти руку на плече','Не треба класти руку на плече.
