INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_11808','Де ти тепер','Музика: Ігор Шамо, Вадим Гомоляка Слова: Борис Палійчук. Виконує: Квітка Цісик, Ніна Шестакова, Таїсія Повалій, Олександр Малінін, Елеонора Яроцька, Марта Шпак','uk','ukraine_before_1917',NULL,NULL,NULL,'Підбір акордів: Nick Falafivka','Місто спить, згасли вогні,
Разом гуляли з тобою всю ніч ми.
Згадка прощання, перші признання...
Де тепер вони?
Ми гадали, зустрічі ждали,
Та пройшли ті дні
Ти сказав: "і в час біди
Дружби такої ніхто не зітре з землі"
Довга розлука, віддалі мука
Ти в душі завжди!
В даль полинеш, все покинеш
Прийдеш знов сюди.
Відгукнись! Де ти в цей час?
Знаю, ти згадував в горі мене не раз...
Весняні ночі стали коротші,
Тільки не для нас
Все промине, в даль полине
Наш любимий вальс.
Наш любимий вальс.','["pisni.org.ua", "cat:dances", "cat:lirychni", "cat:waltzes", "Пісні до танцю", "Пісні про кохання, ліричні", "Вальси"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_11808'), datetime('now')),datetime('now'));
