INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1185101','Через наше село дерево возили','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256',NULL,'Через наше село дерево возили.
Дерево возили, церкву становил(и).

Церкву становили із трьома верхами.
Із трьома верхами, з трьома куполам(и).

З трьома куполами, з трьома місяцями.
З трьома місяцями, з трьома зірницям(и).

Перший місяць ясний - а той Іван красний.
Перша зірка ясна - а та Галя крас(на).

Другий місяць ясний - а той Петро красний.
Друга зірка ясна - та Марія крас(на).

Третій місяць ясний - а той Павло красний.
Третя зірка ясна - а та Ніна крас(на).

Тепер їх узяти та й попарувати.
Калина-малина, ягода червон(а).

Тую Галю взяти - Іванові дати.
Ту Марію взяти та й Петрові дат(и).

А ту Ніну взяти та й Павлові дати.
Калина-малина, ягода червон(а).

На тім Іванові вишита сорочка.
А хто її вишив? Васильова доч(ка).

А на тій і Галі золотий віночок.
А хто ж їй і купив? Романів синоч(ок).','["pisni.org.ua", "cat:kupalski", "Купальські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1185101'), datetime('now')),datetime('now'));
