INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1191426','Ой у полі дуб на дуба звився','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Ой у полі, полі
Дуб на дуба звився,
Добрий був синочок
Доки не женився.

А як оженився
Та вже жінку має,
Він про свою маму
Більше не згадає.

- Сину, мій синочку,
Сину мій вірненький,
Скажи мені правду,
Хто тобі рідненький.

Чи жінка, чи теща,
Чи рідная мати,
Скажи мені правду,
Бо я хочу знати.

- Жінка мені, нене,
Бо моя дружина.
Теща мені рідна,
Бо її родила.

А ти, стара мати,
Мусиш пробачати.
Не хоч пробачати,
Можеш йти із хати.

Ой у полі, полі
Мати жито жала,
Син сказав: "Добридень"
Мати промовчала.

- Мати, моя мати,
Чи ти горда стала,
Я сказав: "Добридень",
А ти промовчала.

- Сину, мій синочку,
Я не горда стала,
Через дрібні сльози
Тебе не пізнала.

- Мати, моя мати,
Покинь жито жати,
Приходи до мене
Віку доживати.

Будеш, моя мати,
Жити у коморі,
Бо на кухні діти,
А жінка в покої.

- Прийшла я до сина,
Не застала вдома,
А моя невістка
Не сказала й слова.

Піду я до дочки,
Вона горе знає,
Дочка приголубить,
Про все розпитає...

Вийшов зять із хати,
Нахмурив бровами:
- Забирайся, тещо,
З своїми речами.

- Я вас годувала,
Як квочка курчата,
Нащо ж мені, діти,
Такая відплата.

Я вас годувала
По двоє, по троє.
Тепер нема місця
Для мене старої.

Дякую вам, діти,
Що ми ся зустріли,
Піду доживати
В домі пристарілих.

Я не хочу, діти,
Вашої зарплати,
Тільки пам''ятайте,
Що є у вас мати.','["pisni.org.ua", "cat:socialno-pobutovi", "Соціально-побутові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1191426'), datetime('now')),datetime('now'));
