INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_118921','Щедрий вечір, добрий вечір','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1971',NULL,'Джерело: "Народні пісні в записах Лесі Українки та з її співу". "Музична Україна" 1971 рік.','Щедрий вечір, добрий вечір,
Добрим людям на весь вечір!
А я знаю що пан дома,
Сидить собі кінець стола.
