INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1191101','Кедь ми прийшла карта *','Українська народна пісня. Виконує: Веселка','uk','ukr_ssr_1919_1991',NULL,'1979','Надав Святослав','Адаптований, українізований варіянт лемківсько-закарпатської пісні Виконує: Веселка Альбом: Веселка 1979','Кедь ми прийшла карта на роковать,
Став я свого неня просити, благать.
Неню ж ти, мій, неню, вчинь ми таку волю - |
Йди за мене служить на ту войну.           | (2)

Кедь ми прийшла карта на роковать
Став я музикантів просити, благать.
Гей ви, музиканти, заграйте ми чардаш,     |
Най си погуляю в той останній раз          | (2)

Стали музиканти чардаш грати,
Стали ми ся сльози з очей лляти, -
Ніхто не заплаче, ні отец ні матка,        |
Лем за мнов заплачуть три дівчатка         | (2)

Ой одна заплаче, бо я її брат,
А друга заплаче, бо я її сват,
А третя заплаче, бо плакати мусить,        |
Бо вона від мене перстень носить           | (2)','["pisni.org.ua", "cat:rekrutski", "Рекрутські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1191101'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1191101','Кедь ми прийшла карта *','Кедь ми прийшла карта на роковать,
Став я свого неня просити, благать.
