INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_1191101_l1','pisniua_1191101','Переглянути варіанти >>','https://www.pisni.org.ua/#variants','external',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_118909','Плаче захмарене небо','Музика: Ярослав Вишиваний Слова: Олександр Демиденко','uk','ukraine_1991',NULL,NULL,'1. З пам''яті; 2. У лузі калина так гарно цвіте. - І.-Ф.: Обласна друкарня, 2000. - С. 32.','Без сумніву, пісня авторська, але стала народною, свого часу була дуже популярною, зокрема, на весіллях. Пісня має дуже стійкий текст, але трапляється різний порядок виконання в''язок, наприклад: 1-4-2-5-3; 1-3-4-2-5 тощо. Одного разу почув на весіллі жартівливе пародійне виконання цієї пісні, коли після кожного непарного рядка співали "в штанах", а після кожного парного - "без штанів".','1. Плаче захмарене небо,
В роздумах клени сумні,
- Нам зустрічатись не треба, -
Стиха ти мовив мені.

Приспів:
Словом мене не пораниш, |
Вірність свою збережу,* |
Хоч ти мене покидаєш,   | (2)
