INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1192606','Пречистая Діва церкву збудувала','Українська народна пісня. Виконує: Кумасеньки','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Пресвятая Діва церкву збудувала.
