INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1192303','Добрий вечір, люди','Музика: Леся Горова Слова: Леся Горова','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Добрий вечір, люди,
Вашій теплій хаті!
Щоб були ви завжди
Щедрі і багаті!
Хай Різдво Христове
Вас благословляє,
Бог ся рождає!

Всім колядникам
Ви відчиняйте двері
І просіть до столу,
До своєй вечері.
Хай у вашій хаті
Нині все співає,
Бог ся рождає!

Гарно колядуйте
І святкуйте нині,
Ми бажаєм щастя
Вашій всій родині!
Весь наш рід великий |
Нині освятився,      |
Бог народився!       | (2)','["pisni.org.ua", "cat:christian", "Пісні на християнську тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1192303'), datetime('now')),datetime('now'));
