INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1193202','Коли звізда ясна','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Коли звізда ясна
