INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1195000','А в кривого танця','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'RA-Media.uaprom.net',NULL,'А в Кривого Танця
