INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1198000','По селу ідуть козаки','Музика: Віталій Мороз Слова: Віталій Мороз. Виконує: П. Сеник','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'У селі понад ярочком стара бабця прожива,
У старенькій сірячині по двору вона гуля,
Образи свої старенькі ганчіркою протира,
Біля чистого віконця стару пісню заспіва.

Приспів:
По селу ідуть козаки
І далекії в них шляхи,
Проводжає їх все село
І дай Боже, щоб щастя було!

У село до баби Насті приїжджаєте, коли
Чай із липою заварять сядуть разом за столи,
Пам''ятає наша бабця бойовії всі часи,
Як жили і, як кохали, поверталися з війни!

Приспів. (2)

У селі понад ярочком стара бабця прожива,
У старенькій сірячині по двору вона гуля,
Гляне на портрет Шевченка і сльозу вона втира,
Бо ніколи, бо ніколи наша слава не вмира!

Приспів. (3)','["pisni.org.ua", "cat:himny-marshi", "cat:kozacki", "Гимни та марші", "Козацькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1198000'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1198000','По селу ідуть козаки','У селі понад ярочком стара бабця прожива,
