INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_1198000_l1','pisniua_1198000','YouTube','https://www.youtube.com/watch?v=-64eA-aQMjc','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1198323','Ангели в небі Господа славлять',NULL,'uk','ukraine_1991',NULL,NULL,NULL,NULL,'Ангели в небі Господа славлять,
Славу достойную Богу несуть, Богу несуть:
Вічная слава, вічная слава,
Вічная слава, слава Христу! Слава Христу!

Хочеться з ангельським співом з''єднатися,
В хорі відкуплених, спасенних Христом.
І серцем Господу, Богу Єдиному
Христу Спасителю славу несем.

Тут на землі Його церква так томиться,
В небі стремиться до Нареченого.
О, гряди, Господи, бачиш невіста жде,
Тобі Єдиному славу несе.

Агнець прославлений, Царственний Божий Син,
Дивний Христос Господь в небі нас жде.
І серце Господу, Богу Єдиному
Христу Спасителю славу несе.','["pisni.org.ua", "cat:christian", "Пісні на християнську тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1198323'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1198323','Ангели в небі Господа славлять','Ангели в небі Господа славлять,
Славу достойную Богу несуть, Богу несуть:
Вічная слава, вічная слава,
Вічная слава, слава Христу! Слава Христу!

Хочеться з ангельським співом з''єднатися,
В хорі відкуплених, спасенних Христом.
І серцем Господу, Богу Єдиному
Христу Спасителю славу несем.

Тут на землі Його церква так томиться,
В небі стремиться до Нареченого.
О, гряди, Господи, бачиш невіста жде,
Тобі Єдиному славу несе.

Агнець прославлений, Царственний Божий Син,
Дивний Христос Господь в небі нас жде.
І серце Господу, Богу Єдиному
Христу Спасителю славу несе.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1197707','Перший дзвоник','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Шкільнії роки ми будем пам''ятати,
Ще з того дня,
Як вперше мама з татом
За ручки в перший клас
Вели колись до школи -
Не забувається таке, мабуть, ніколи.
І перший раз ми святкували в школі
У великому, здавалося б, нам колі.
Той перший дзвоник так дзвенів довкола,
Що не забудеться нікому і ніколи!

Приспів:
І квітів море
Було у школі,
Той перший дзвоник
Дзвенів довкола
На сотні миль,
На віки хвиль!

І пісня линула над нами й окриляла
Майбутні мрії і з собою закликала
І радість вперше в школі нам подарувала,
Та щоб ніколи ми про це не забували!

Приспів. (2)

На сотні миль, на віки хвиль!
На сотні миль, на віки хвиль!','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1197707'), datetime('now')),datetime('now'));
