INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1199529','Ялино','Українська народна пісня. Виконує: Фольктеатр Остапа Стахіва','uk','ukr_ssr_1919_1991',NULL,NULL,NULL,NULL,'Ялино, ялино, я в гай по калину
