INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_119505','Ой ходить сон коло вікон','Українська народна пісня. Виконує: Квітка Цісик, Квітка Цісик, Оксана Білозір','uk','ukr_ssr_1919_1991',NULL,'1971','"Народні пісні в записах Лесі Українки та з її співу". 1971 рік "Музична Україна"',NULL,'Ой ходить сон коло вікон,
А дрімота — коло плота.
Питається сон дрімоти:
— А де будем ночувати?
— Де хатонька теплесенька,
Де дитина малесенька,—
Там ми будем ночувати,
Дитиночку колихати.

Ой на кота та воркота,
На дитину та й дрімота,
Котик буде воркотати,
Дитинонька буде спати','["pisni.org.ua", "cat:dytyachi", "cat:kolyskovi", "cat:narodni", "Дитячі пісні", "Колискові", "Народні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_119505'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_119505','Ой ходить сон коло вікон','Ой ходить сон коло вікон,
А дрімота — коло плота.
Питається сон дрімоти:
— А де будем ночувати?
— Де хатонька теплесенька,
Де дитина малесенька,—
Там ми будем ночувати,
Дитиночку колихати.

Ой на кота та воркота,
На дитину та й дрімота,
Котик буде воркотати,
Дитинонька буде спати');
