INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1198622','День подяки',NULL,'uk','ukraine_1991',NULL,NULL,NULL,NULL,'У нас сьогодні День Подяки
Творцеві за дари усякі:
Em
За хліб, повітря і за воду
Для нас і нашого народу.

Hm
За сонце, що так гарно гріло,
A
Що в нас ніщо не погоріло,
За дощ, що зрошував насіння,
За всі Його благословіння.

Що кожний день нам сходить сонце,
Пташки співають нам в віконце.
За ліс і луки, всі простори,
Що в темну ніч нам сяють зорі.

Коли закінчим сіять, жати,
Покличуть нас відпочивати.
Земна закінчиться дорога,
Там будем вічно славить Бога.','["pisni.org.ua", "cat:christian", "Пісні на християнську тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1198622'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1198622','День подяки','У нас сьогодні День Подяки
Творцеві за дари усякі:
Em
За хліб, повітря і за воду
Для нас і нашого народу.

Hm
За сонце, що так гарно гріло,
A
Що в нас ніщо не погоріло,
За дощ, що зрошував насіння,
За всі Його благословіння.

Що кожний день нам сходить сонце,
Пташки співають нам в віконце.
За ліс і луки, всі простори,
Що в темну ніч нам сяють зорі.

Коли закінчим сіять, жати,
Покличуть нас відпочивати.
Земна закінчиться дорога,
Там будем вічно славить Бога.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1202220','Крутянські зорі','Музика: Василь Дунець Слова: Олександр Гавриленко і Василь Дунець. Виконує: Василь Дунець','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'Авторське подання - СD','Аранжування - Андрій Стадницький Запис - Олександр Третяк Бек-вокал - Роман Рудий','Дивлюсь я на зорі. О ні це не зорі,
Це лицарів очі ясні.
Вкраїно до тебе вернулись
Твої відчайдушні сини.

Сніги цвіли. Три сотні молодців
Прийшли в поля крутянські - золотії,
Щоб зупинити хижих ворогів,
Які ярмо несли всій Україні.
Нерівні сили стали віч на віч,
Від страху навіть сонце заховалось,
Та легені не кинулися пріч -
Вони в цей день нікого не боялись.

І грянув бій! Нерівний, лютий бій!
Неначе змії, кулі засичали,
Орда повзла, немов осиний рій,
А хлопці до загибелі стояли!
Червоний дощ тоді на землю впав,
Сніги від крові на полях розтали,
Ніхто із них життя не шкодував,
Бо Україну й волю захищали...

...А коли сонце визирнуло з хмар -
Жахнулось від побаченого в полі.
Всі триста на України вівтар
Життя поклали, за майбутніх волю.
І заридала гірко Україна,
І десь забились матері у горі,
А очі юних, в цю лиху годину,
Засяяли над полем наче зорі...

Але усе минає, час біжить,
І капля, хоч мала, та камінь точить.
І воля під кайданами не спить,
Вона росте і сил у неї досить.
Хто в світ прийшов з мечем - від нього вмре,
А Бог молитви наші ще почує,
І кожен із трьохсот тих оживе,
І Україну молодість врятує!

Далі звучить 8 тактів Державного Гімну України','["pisni.org.ua", "cat:kruty", "Пісні пам''яті Героїв бою під Крутами"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1202220'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1202220','Крутянські зорі','Дивлюсь я на зорі. О ні це не зорі,
