INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_12101','Троянди на пероні','Музика: Анатолій Горчинський Слова: Олександр Богачук. Виконує: Крайня Хата, Анатолій Горчинський, Віктор Мазаний, Анастасія Жукова, Гурт Wszystko, Андрій Євтушенко, Гурт Мрія, Юлія Пєшковська, Оксана Пекун, Валентина Купріна','uk','ukraine_before_1917',NULL,NULL,'Співаник для таборів Марійської Дружини','Акорди від piwtorachok.','На пероні, на люднім пероні,
Де розлуки і зустрічі плачуть,
Хтось розсипав троянди червоні,
І, здається, ніхто їх не бачить...
Приспів:
А троянди, а троянди
До людей пелюстками кричать:
"Ми не квіти, ми - кохання
А кохання не можна топтать"
В моїм серці чи біль чи то смуток:
Не зустрів ти мене і сьогодні.
Хтось дарує комусь поцілунок,
А хтось топче троянди червоні...
Приспів.
На пероні, на тихім пероні,
Вже не чути далекого стуку.
Хтось розсипав троянди червоні,
Чи то зустріч свою, чи розлуку...
Приспів.','["pisni.org.ua", "cat:lirychni", "Пісні про кохання, ліричні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_12101'), datetime('now')),datetime('now'));
