INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1226828','У неволі тяжкій','Українська народна пісня. Виконує: Люба Клопотовська','uk','ukraine_before_1917',NULL,NULL,'власна фонотека',NULL,'У неволі тяжкій січовик молодий
Умирав від кривавої рани.
Йому жаль лиш було, що могилу його       |
