INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_121909','Ой гарна я, гарна','Українська народна пісня. Виконує: Раїса Кириченко','uk','ukraine_before_1917',NULL,NULL,'1. В дорогу. Пластовий співаник.- 2-е вид.- Торонто, 1987','Тут у джерелі [1] інший текст (можливо, через помилку): * Най ми ся уступить, шей, гой! ** Ой я така гарна, шей, гой! Підбір акордів: bohdanko@epost.com.ua','Ой гарна я, гарна, як тая горлиця.
Ой гарна я, гарна, як тая горлиця.
Най ми ся уступить, гей, гой!             |
Най ми ся уступить, гей, гой! *           | (2)
Най ми ся уступить, з путя парадниця.     |

З путя парадниця, з поля робітниця.
З путя парадниця, з поля робітниця.
Ой я така гарна, гей, гой!                |
Ой я така гарна, гей, гой! **             | (2)
Ой я така гарна, як в небі зірниця.       |

Гарна була, гарна, не було ми пари.
Гарна була, гарна, не було ми пари.
