INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1229202','На заручини-вечір','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1969','"Пісні Тернопільщини". Пісенник. - Вип.1. - Київ: Муз. Україна, 1989.','М. Прокопчук, 1969, Обич Шумського р-ну. Від Ганни Юрчук (1911, 2 кл). Мелодію розшифрував В. Подуфалий. 136 Джерело: Пісні Тернопільщини: Календарно-обрядова та родинно-побутова лірика: Пісенник. Вип.1. / Упоряд.: С.І.Стельмащук, П.К.Медведик. Вступ. ст. П.Медведика. — К.: Муз. Україна, 1989.','На заручини-вечір     | (2)
Соловейко щебече.

А зозуленька кує,     | (2)
Нехай матінка чує.

Нехай матінка знає,   | (2)
З ким дочку заручає.

Як буде п''яниченька,  | (2)
То проп''є кониченька.

Як буде недбайлиця,   | (2)
То здійме красоньку з лиця.

З личенька рум''яного, | (2)
Зі стану дівоцького.','["pisni.org.ua", "cat:vesilni", "Весільні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1229202'), datetime('now')),datetime('now'));
