INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1210606','Весільна пісня','Виконує: Олександр Пономарьов','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Два серця, дві душі
Сплелися воєдино
"Люблю!" - сказала ти,
І відголоском лине
У відповідь моє "Люблю!
Люблю тебе я назавжди!"

Приспів:
Серця одного ми - дві половинки:
Я і ти - королева моя!
А в очах не сльози,
То любові краплинки,
Бо ніхто не любить тебе так, як я!

Небесна і легка,
Моя голубонька!
"Люблю!" - сказала ти,
І відголоском лине
У відповідь моє "Люблю!
Люблю тебе я назажди!"

Приспів.','["pisni.org.ua", "cat:vesilni", "Весільні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1210606'), datetime('now')),datetime('now'));
