INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1229505','На абордаж - на зайця','(маршова мисливська жартівлива пісня). Музика: Євген Заставний Слова: Т. Василько','uk','ukraine_1991',NULL,NULL,'Авторське подання: Т. Василько. Гомін підгір''я (альманах) №8. - 2009. - С. 116 - 135.',NULL,'Поля, ліси, вузькі стежки,
За кроком крок, за кроком крок:
Рівняння браво на курок! -
Веселий ми народ - мисливці.

Приспів:
Мисливці - нечувані сміливці, -
Завзяттям сповнені серця;
Мисливці, патрони в пантронташ,
Йдемо на абордаж - на зайця!

Чи вітер, сніг - нам доля вслід,
За кроком крок, а разом два:
Природа дика ще жива,
Бо бережуть її мисливці!

Приспів.

Якщо не йти, то не дійти,
За кроком крок, вперед, вперед,
І єгер наш, тварин повпред,
Дає останній інструктаж.

Приспів.','["pisni.org.ua", "cat:himny-marshi", "Гимни та марші"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1229505'), datetime('now')),datetime('now'));
