INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1233101','Купальський вінок','Музика: Ірина Доля Слова: Ірина Доля. Виконує: Ірина Доля, тріо','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Бачу у небі свою зорю,
Світить вона чи ні,
Зіронько мила, любов мою
Ти принеси мені!

Приспів:
Я вінок в Купальську ніч |
По воді пускала,         |
А до тебе мати знов      |
Мене не пускала.         | (2)

Плину по небу у ніч ясну
В місячному човні,
Зорі колишуть усе до сну,
Любий, наснись мені!

Приспів.','["pisni.org.ua", "cat:kupalski", "Купальські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1233101'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1233101','Купальський вінок','Бачу у небі свою зорю,
Світить вона чи ні,
Зіронько мила, любов мою
Ти принеси мені!

Приспів:
Я вінок в Купальську ніч |
По воді пускала,         |
А до тебе мати знов      |
Мене не пускала.         | (2)

Плину по небу у ніч ясну
В місячному човні,
Зорі колишуть усе до сну,
Любий, наснись мені!

Приспів.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_1233101_l1','pisniua_1233101','YouTube','https://www.youtube.com/watch?v=7caHdMgTVPg','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_123101','Сину, качки летять *','Музика: Олександр Білаш Слова: Михайло Ткач. Виконує: Володимир Турець','uk','ukraine_1991',NULL,NULL,NULL,NULL,'На світанку сина
Сповивала мати
В час, коли про долю
Зорі лебедять.
Глянь, моя дитино,
Через Україну,
Через нашу хату
Вже качки летять.

На світанку сину
Нашептала мати:
Під Чумацьким шляхом
Чумаченьки сплять.
Встань моя дитино,
Через Україну,
Через нашу хату
Вже качки летять.

На світанку, сину,
Буду наслухати,
Коли в небі синім
Крила зашумлять.
Прилітай, дитино,
Через Україну,
Через нашу хату
Вже качки летять.

На світанку, сину,
Важко не діждати,
А ще важче в ночі
Очі видивлять.
Не блукай, дитино!
Через Україну,
Через нашу хату
Вже качки летять','["pisni.org.ua", "cat:nostalgia", "cat:pro-batkiv", "Пісні з ностальгічними мотивами", "Пісні про любов до батьків"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_123101'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_123101','Сину, качки летять *','На світанку сина
