INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1228323','Кругом, женчики, кругом','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Збірник художніх творів "Стожари"',NULL,'Кругом, женчики, кругом,
Понад зеленим лугом.
Женчики кружинають,
Пшениці дожинають.

Кінець нивоньці, кінець,
Будемо плести вінець.
То з жита, то з барвінку
На хорошую дівку.

В нашого господаря
Та золотая брама.
Мальовані одвірки,
Зробим сьогодні обжинки.

Світи, місяцю, з рога,
Щоб була видна дорога.
Щоб з неї не зблудити,
Віночка не згубити.','["pisni.org.ua", "cat:obzhynkovi", "Обжинкові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1228323'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1228323','Кругом, женчики, кругом','Кругом, женчики, кругом,
Понад зеленим лугом.
Женчики кружинають,
Пшениці дожинають.

Кінець нивоньці, кінець,
Будемо плести вінець.
То з жита, то з барвінку
На хорошую дівку.

В нашого господаря
Та золотая брама.
Мальовані одвірки,
Зробим сьогодні обжинки.

Світи, місяцю, з рога,
Щоб була видна дорога.
Щоб з неї не зблудити,
Віночка не згубити.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1233725','Балада про материнські сльози','Слова: Леся Карпінська','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Речитатив:
Щойно зійде сніг на Прикарпатті,
А на луках понад стежками
З''являються маленькі білі квіточки -
Маргаритки. - Люди називають їх
Материнськими сльозами...

Жила тут колись удова,
Мала три сини - парубки,
Засмутилась рідна земля -
Край татарські хани знайшли.
Осідлали хлопці коней,
Благословила мати у путь,
Три сльози скотились з очей —
Розбудили силу і лють.

Материнські сльози, маргаритки, —
Удовині сльози сивих літ...
Материнські сльози, маргаритки, —
Ранній дивоцвіт.

Два сини упали в січі,
Третього в полон хан повіз,
Наче килим, сніг уночі,
Не спинив її босих ніг.
Бігли сльози рясним дощем,
Зводили потоки услід,
Повернулись весни, а щем...
Заквітчав стежки в білий квіт.

Материнські сльози, маргаритки, —
Удовині сльози сивих літ...
Материнські сльози, маргаритки, —
Весен ранній квіт...

Речитатив:
Якщо ж у провесінь
Ти побачиш цю маленьку квіточку —
Не рви її, спинись...

"Я ж бо у весни перший сон -
Зашепоче мило вона. -
Не бери мене у полон,
Матері-вдови я сльоза..."','["pisni.org.ua", "cat:pro-ditey", "Пісні про любов до дітей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1233725'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1233725','Балада про материнські сльози','Речитатив:
Щойно зійде сніг на Прикарпатті,
А на луках понад стежками
З''являються маленькі білі квіточки -
Маргаритки. - Люди називають їх
Материнськими сльозами...

Жила тут колись удова,
Мала три сини - парубки,
Засмутилась рідна земля -
Край татарські хани знайшли.
Осідлали хлопці коней,
Благословила мати у путь,
Три сльози скотились з очей —
Розбудили силу і лють.

Материнські сльози, маргаритки, —
Удовині сльози сивих літ...
Материнські сльози, маргаритки, —
Ранній дивоцвіт.

Два сини упали в січі,
Третього в полон хан повіз,
Наче килим, сніг уночі,
Не спинив її босих ніг.
Бігли сльози рясним дощем,
Зводили потоки услід,
Повернулись весни, а щем...
Заквітчав стежки в білий квіт.

Материнські сльози, маргаритки, —
Удовині сльози сивих літ...
Материнські сльози, маргаритки, —
Весен ранній квіт...

Речитатив:
Якщо ж у провесінь
Ти побачиш цю маленьку квіточку —
Не рви її, спинись...

"Я ж бо у весни перший сон -
Зашепоче мило вона. -
Не бери мене у полон,
Матері-вдови я сльоза..."');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1230404','Дас іст гуд фантастіш','Музика: Михайло Хома, Олег Турко Слова: Михайло Хома, Олег Турко. Виконує: DZIDZIO','uk','ukraine_before_1917',NULL,NULL,'відеозапис',NULL,'Тобі вже вісімнадцять
І ти на всьо готова,
А ми не говорили
Про секс ще ані слова.
Я вже не можу більше
Ту тєму відкладати,
Мені вже надоїло
І я махав чекати.

Приспів
Das іst good fantastіsch, |
Das іst good, ya, ya!     |
Чуєш, хочу я!             | (2)

Я про любов глибоку
Німецький фільм дивився,
Реально еротичний
Про тебе сон приснився.
Мені ти шепотіла:
Ich lіebe dіch ja wohl...
А я відповідав
Любовних слів пароль.

Приспів.

Якась твоя подруга
До мене подзвонила,
Мене чомусь без тебе
До себе запросила.
Ти маєш зрозуміти:
Я мушу взрослим стати,
Мені вже надоїло
І я махав чекати.

Приспів.','["pisni.org.ua", "cat:zhartivlyvi", "Жартівливі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1230404'), datetime('now')),datetime('now'));
