INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1246323','Провoджала мати','Українська народна пісня. Виконує: Кубанський Козачий Хор','uk','ukraine_before_1917',NULL,NULL,'інтернет',NULL,'Проводжала мати сина у солдати,
Проводжала мати сина у солдати,              |
Молоду невістку - в поле жито жати.          | (2)

Йди ти, невістко, в поле жито жати,
Йди ти, невістко, в поле жито жати           |
Та й не повертайся до моєї хати.             | (2)

Вона жала, жала, жала-вижинала,
Вона жала, жала, жала-вижинала,              |
Поки до світ сонця тополиной стала.          | (2)

Прийшов син до хати: "Здраствуй, рідна мати,
Прийшов син до хати: "Здраствуй, рідна мати, |
Що ж то за туполя, стоїтъ серед поля?"       | (2)

Не питай ти, сину, про тою причину,
Не питай ти, сину, про тою причину,          |
