INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1248725','Козацький дозор','Слова: Вячеслав Зимин. Виконує: Камерний хор Кредо','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Ой, сумує дівчина та й гірко плаче,
У далекому дозорі її козаче,
Головоньки не склади на чужбині,
Бо потрібен ти живий своїй родині.

Не сумуй, моя кохана, я ж з по-заранку,
Та й надіну твій дарунок - вишиванку,
Не страшні тепер мені воріженьки,
Повернуся я живий до тебе й неньки.

Аж тут сурма засурмила - на бій скликає,
Ген на обрії дими, там степ палає,
Отаман свого коня пустив галопом,
Поскакали козаки буджацьким степом.

Степ палає і жнива, хати палають,
Вороги жінок дітей в полон вганяють,
Тут із диму козаки налетіли,
Порубали ворогів здобич відбили.

Чує дівчина здалля музика грає,
Така пісня та сумна, аж серце крає,
Аж тут сурма засурмила веселенько,
Повернувся із походу козаченько...','["pisni.org.ua", "cat:kozacki", "Козацькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1248725'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1248725','Козацький дозор','Ой, сумує дівчина та й гірко плаче,
У далекому дозорі її козаче,
Головоньки не склади на чужбині,
Бо потрібен ти живий своїй родині.

Не сумуй, моя кохана, я ж з по-заранку,
Та й надіну твій дарунок - вишиванку,
Не страшні тепер мені воріженьки,
Повернуся я живий до тебе й неньки.

Аж тут сурма засурмила - на бій скликає,
Ген на обрії дими, там степ палає,
Отаман свого коня пустив галопом,
