INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1251725','Свято, друже, зустрiчай!','Слова: Тамара Маршалова','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Білий сніг блищить довкола,
Мчать із гірочки ґринджоли.
На ґринджолах Миколай.
Свято, друже, зустрічай!

А, як ще й слухняним був,
Миколай це не забув.
Привезе, повір, чудові
Подаруночки святкові!

Білий сніг блищить довкола,
Мчать із гірочки ґринджоли.
Сумувати покидай,
Миколая привітай!

Бо, як ще й слухняним був,
Миколай це не забув,
І привіз тобі чудові
Подаруночки святкові!','["pisni.org.ua", "cat:svyatyy-mykolay", "Пісні про Святого Миколая"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1251725'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1251725','Свято, друже, зустрiчай!','Білий сніг блищить довкола,
Мчать із гірочки ґринджоли.
На ґринджолах Миколай.
Свято, друже, зустрічай!

А, як ще й слухняним був,
Миколай це не забув.
Привезе, повір, чудові
Подаруночки святкові!

Білий сніг блищить довкола,
Мчать із гірочки ґринджоли.
Сумувати покидай,
Миколая привітай!

Бо, як ще й слухняним був,
Миколай це не забув,
І привіз тобі чудові
Подаруночки святкові!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1252024','Погода в школі','Музика: Лариса Доліна Слова: Ігор Федчишин','uk','ukraine_1991',NULL,NULL,'http://www.poetryclub.com.ua/getpoem.php?id=367842','Рімейк на пісню Ларіси Доліної "Погода в доме".','У нас сьогодні жовтень золотиться -
Ми відмічаєм свято вчителів.
Нехай вам, любі, у житті щаститься
І школа буде, наче другий дім.

Приспів:
Найперш за все - погода в школі,
Щоб в її вікнах сонця дар,
Щоб поміж нас вітри ніколи
Не нагнітали темних хмар.

Чи то лиш осінь, чи весна грайливо
Нас у похід за мудрістю позве -
Нам не забути цих років щасливих
І ваше слово щире і святе.

Приспів.

І щоб не відбувалося навколо,
Які б зима не намела сніги -
Спішити завжди будем в рідну школу,
Хоч і будем вже зватися - батьки.

Приспів.','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1252024'), datetime('now')),datetime('now'));
