INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1242127','Ой, верше, мій верше','Українська народна пісня. Виконує: Леся Горлицька','uk','ukr_ssr_1919_1991',NULL,'1991','альбом "З Лемківського краю" Леся Горлицька, 2008 р.','Пісня записана від лемкині Вільчак Євгенії Миколаївни (шкільної вчительки з математики), 1991, с. Пишківці Бучацький район.','Ой, верше, мій верше,
Мій зелений верше,
Юж мі так не буде | (2)
Як мі било перше.

А перше мі било,
Барз мі дорбі било
У своєй мамички   | (2)
Не ходити било.

Не ходити било
Кадиль я ходила,
Не любити било    | (2)
Кого я любила.

Не ходити било
Горами, лісами,
Не любити хлопців | (2)
З чорними очами.

А Йванкови очи
Ходять по убоги,
А мої за нима     | (2)
Здали с ме ся з нима.

На єдно ся здаме
Чорни очка маме,
На друге ся здаме | (2)
Жадно нич не маме','["pisni.org.ua", "cat:lemkivski", "Лемківські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1242127'), datetime('now')),datetime('now'));
