INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1251404','Для маленького Iванка','Слова: Тамара Маршалова','uk','ukraine_before_1917',NULL,NULL,'авторське подання',NULL,'Для маленького Іванка
Склала мати колисанку.
Колисанку дивну склала,
Місяць й зорі повплітала...

Поміж зорями ясними
Річка снів дитячих плине,
А у річці - місяць-човен,
Казочок чарівних повен...

Човен хвилею гойдає,
Птах-казкар увись злітає,
Поспішає до Іванка,
Заспівати колисанку:

- Люлі-бай, моє хороше,
Снів спускається пороша,
Хутко в ліжечко лягай,
Казку гарну оглядай...
Люлі-бай...','["pisni.org.ua", "cat:kolyskovi", "Колискові"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1251404'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1251404','Для маленького Iванка','Для маленького Іванка
Склала мати колисанку.
Колисанку дивну склала,
Місяць й зорі повплітала...

Поміж зорями ясними
Річка снів дитячих плине,
А у річці - місяць-човен,
Казочок чарівних повен...

Човен хвилею гойдає,
Птах-казкар увись злітає,
Поспішає до Іванка,
Заспівати колисанку:

- Люлі-бай, моє хороше,
Снів спускається пороша,
Хутко в ліжечко лягай,
Казку гарну оглядай...
Люлі-бай...');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1251127','Пора, мати, жито жати','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Українські народні пісні з нотами. Кого люблю — Мій буде / Упоряд. Г. І. Ганзбурґ; Худож.-оформлювач Л. Д. Киркач. — Харків: Фоліо, 2004. — 287 с.',NULL,'Пора, мати, жито жати:
Колос похилився,
Пора дочку заміж дати:
Голос одмінився.

Хоч колосок похилився,
Стебло зелененьке,
Хоч голосок одмінився,
Личко молоденьке.

Посилає мене мати
У степ жито жати,
Аж там чумак воли пасе, —
Став зо мною жартувати.

Жартуй, жартуй, чумаченьку,
Жартуй, коли любиш,
як підеш у дорогу,
То мене забудеш!

Не забуду, моя мила,
Буду поспішати,
А як прийду додомоньку,
Сватів буду слати!

Весна-красна наступає,
Із стріх вода капле,
Молодому чумакові
Шлях-дорога пахне.

У, неділю ранесенько,
Саме на схід сонця,
Заплакала дівчинонька,
Глядячи в віконце:

Чому мене, моя нене,
Рано не збудила,
А як тая чумачина
З села виїздила?

Тим я тебе, моя доню,
Рано не збудила, —
Попереду твій миленький, —
Щоб ти не тужила!

Ти думаєш, моя нене,
Що я й так не плачу?
За дрібними слізоньками
Вже й світу не бачу!

Ой, я б була, моя нене,
Зовсім не тужила,
Коли б тільки миленькому
Доленька служила!

Ти думаєш, моя нене,
Що й так не журюся?
Ой, як вийду за ворота, —
Од вітру валюся!','["pisni.org.ua", "cat:chumacki", "Чумацькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1251127'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1251127','Пора, мати, жито жати','Пора, мати, жито жати:
Колос похилився,
Пора дочку заміж дати:
Голос одмінився.

Хоч колосок похилився,
Стебло зелененьке,
Хоч голосок одмінився,
Личко молоденьке.

Посилає мене мати
У степ жито жати,
Аж там чумак воли пасе, —
Став зо мною жартувати.

Жартуй, жартуй, чумаченьку,
Жартуй, коли любиш,
як підеш у дорогу,
То мене забудеш!

Не забуду, моя мила,
Буду поспішати,
А як прийду додомоньку,
Сватів буду слати!

Весна-красна наступає,
Із стріх вода капле,
Молодому чумакові
Шлях-дорога пахне.

У, неділю ранесенько,
Саме на схід сонця,
Заплакала дівчинонька,
Глядячи в віконце:

Чому мене, моя нене,
Рано не збудила,
А як тая чумачина
З села виїздила?

Тим я тебе, моя доню,
Рано не збудила, —
Попереду твій миленький, —
Щоб ти не тужила!

Ти думаєш, моя нене,
Що я й так не плачу?
За дрібними слізоньками
Вже й світу не бачу!

Ой, я б була, моя нене,
Зовсім не тужила,
Коли б тільки миленькому
Доленька служила!

Ти думаєш, моя нене,
Що й так не журюся?
Ой, як вийду за ворота, —
Од вітру валюся!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_125828','Віддайте мову *','Музика: Едуард Драч Слова: Едуард Драч. Виконує: Едуард Драч','uk','ukraine_1991',NULL,NULL,'За аудіозаписом концерту в Москві 19 березня 1989 року.',NULL,'Не лиш герої на землі зростають,
Є у вітчизни і такі сини,
Котрим і Батьківщина не святая,
Святі їм тільки гроші і чини.

Такий глаголить: Я слуга народу!
Але народу тим цей служить друг,
Що нишком нищить мову і природу,
Народ свій обертаючи на слуг.

Такі загнали в села рідне слово
І там його вже тягнуться добить
Аби забрати пам''ять в нас і мову,
А їх не мають нині лиш раби.

Віддайте мову — не прохання, а наказ!
Віддайте мову, нашу пам''ять і оплот!
Віддайте мову, і не колись, а в цей же час!
Вмре мова — і ми щезнем як народ!

Було нелегко мову в нас забрати,
Котра корінням в Батьківській землі.
Сам хан Батий не зміг її стоптати, —
Проте народу слуги все змогли...

Вони зробили з мови непрестижну,
Забравши з ВУЗів, шкіл і установ;
Нас спонукали кожним днем і тижнем
До зради найспівучішої з мов.

Нам пильність присипали побрехеньки,
Що ми в тій зраді майже рай знайшли.
Вставайте, козаченьки-хмельниченки,
Поки ми спали, мову ізвели!

Віддайте мову — не прохання, а наказ!
Віддайте мову, прорубайте в серці лід!
Віддайте мову, і не колись, а в цей же час!
Лиш мовою живий козацький рід!

Хто ми для них? - Прості аборигени,
Але в тім слові величезний зміст,
Бо в землю повростали наші гени -
Це навіть крізь асфальт великих міст.

Хазяїн хто? - Чиновничі конклави
Чи ти, абориген землі ції?
Це справжній бій, хоч, власне, не кривавий,
Проте і не найлегший із боїв.

Ми в тім бою ще скажем своє слово
Про Чигирин, про Чернівці і Крим,
Та головне - відвоювати мову
У котрій глас народу крізь віки.

Віддайте мову — не прохання, а наказ!
Віддайте мову, нашу пам''ять і оплот!
Віддайте мову, і не колись, а в цей же час!
Лиш в мові вічно житиме народ!

Брати, на нас ви не дивіться скоса -
За своє кровне бій іде у нас:
Сьогодні в нас косою мову скосять,
А завтра лишень приймуться за вас!

Це буде кращий в світі братства прояв,
Коли у пісню зіллються слова,
І встане брат за брата рідну мову,
І хор тисячоголосий заспіва!

Віддайте мову — не прохання, а наказ!
Віддайте мову, нашу пам''ять і оплот!
Віддайте мову, і не колись, а в цей же час!
Лиш в мові вічно житиме народ!

Віддайте мову...
Віддайте мову...
Віддайте мову...
Лиш в мові вічно житиме народ!','["pisni.org.ua", "cat:bardivski", "cat:pisni-pro-movy", "cat:suspilno-politychni", "Бардівські пісні", "Пісні про рідну мову", "Суспільно-політичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_125828'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_125828','Віддайте мову *','Не лиш герої на землі зростають,
Є у вітчизни і такі сини,
Котрим і Батьківщина не святая,
Святі їм тільки гроші і чини.

Такий глаголить: Я слуга народу!
Але народу тим цей служить друг,
Що нишком нищить мову і природу,
Народ свій обертаючи на слуг.

Такі загнали в села рідне слово
І там його вже тягнуться добить
Аби забрати пам''ять в нас і мову,
А їх не мають нині лиш раби.

Віддайте мову — не прохання, а наказ!
Віддайте мову, нашу пам''ять і оплот!
Віддайте мову, і не колись, а в цей же час!
Вмре мова — і ми щезнем як народ!

Було нелегко мову в нас забрати,
Котра корінням в Батьківській землі.
Сам хан Батий не зміг її стоптати, —
Проте народу слуги все змогли...

Вони зробили з мови непрестижну,
Забравши з ВУЗів, шкіл і установ;
Нас спонукали кожним днем і тижнем
До зради найспівучішої з мов.

Нам пильність присипали побрехеньки,
Що ми в тій зраді майже рай знайшли.
Вставайте, козаченьки-хмельниченки,
Поки ми спали, мову ізвели!

Віддайте мову — не прохання, а наказ!
Віддайте мову, прорубайте в серці лід!
Віддайте мову, і не колись, а в цей же час!
Лиш мовою живий козацький рід!

Хто ми для них? - Прості аборигени,
Але в тім слові величезний зміст,
Бо в землю повростали наші гени -
Це навіть крізь асфальт великих міст.

Хазяїн хто? - Чиновничі конклави
Чи ти, абориген землі ції?
Це справжній бій, хоч, власне, не кривавий,
Проте і не найлегший із боїв.

Ми в тім бою ще скажем своє слово
Про Чигирин, про Чернівці і Крим,
Та головне - відвоювати мову
У котрій глас народу крізь віки.

Віддайте мову — не прохання, а наказ!
Віддайте мову, нашу пам''ять і оплот!
Віддайте мову, і не колись, а в цей же час!
Лиш в мові вічно житиме народ!

Брати, на нас ви не дивіться скоса -
За своє кровне бій іде у нас:
Сьогодні в нас косою мову скосять,
А завтра лишень приймуться за вас!

Це буде кращий в світі братства прояв,
Коли у пісню зіллються слова,
І встане брат за брата рідну мову,
І хор тисячоголосий заспіва!

Віддайте мову — не прохання, а наказ!
Віддайте мову, нашу пам''ять і оплот!
Віддайте мову, і не колись, а в цей же час!
Лиш в мові вічно житиме народ!

Віддайте мову...
Віддайте мову...
Віддайте мову...
