INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_125202','Перепелонько біла!','Українська народна пісня','uk','ukraine_before_1917',NULL,'1913','Колесса Ф. Шкільний співаник. З педагогічної спадщини композитора.- Київ: Музична Україна, 1991.- 224 с.','Першоджерело: Колесса Ф. Обжинки. Етнографічна картина у піснях народних на хор мішаний. Львів, 1913.- с. 20','1. Перепелонько біла!
Де ж ти будеш сиділа?
Ні жита, ні пшениці
На господаревій ниві.

2. Перепелонько мала!
Де ж ся будеш ховала?
Ми жито все пожали
І в снопи пов''язали.

3. Вийди, господарю, вийди,
Віночок з голови здійми!
Віночок на кілочок,
Женчикам на таночок.

4. А нема ґазди дома,
Поїхав до Львова
Мед-пиво купувати,
Женчиків частувати.    Мелодія для 1 і 2 голосу','["pisni.org.ua", "cat:obzhynkovi", "Обжинкові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_125202'), datetime('now')),datetime('now'));
