INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_126101','Навкруг Чигирину','Українська народна пісня. Виконує: Рутенія, Кость Єрофєєв','uk','ukraine_before_1917',NULL,NULL,'За аудіозаписом концерту частини гурту "Рутенія" в Москві 1988(89) року.','Назву пісні слід уточнити. Виконують: гурт "Рутенія", Кость Єрофєєв. Автори пісні, ймовірно, в середовищі тодішнього гурту "Рутенія" (Анатолій Сухий, Кость Єрофєєв). Акорди записано на слух з аудіо. Тональність оригінальна. * Тут, можливо, інакше: "Розривають груди її сестер руки". Підбір акордів: bohdanko (pisni.org.ua)','Навкруг Чигирину   по степу кургани -
Там могила скіфа, слава козакам,
Вони пам''ятають   червоні жупани,
Чули голос Гонти   і Залізняка.
Вони пам''ятають   червоні жупани,
Чули голос Гонти   і Залізняка.

З Чернечої кручі чути стогін болю,
Подивись, Тарасе, на дітей своїх,
Що забули мову, розіп''яли волю,     |
Нині топчуть славу прадідів святих. |(x2)

Глянь на Україну, що в сім''ї єдиній,
В сім''ї вольній новій розцвіла, як сад, -
Обриває вітер з того саду квіти    |
І по всьому світу пелюстки летять. |(x2)

Що ж нам скажуть люди? Що ж нам скажуть внуки?
Хто ще на Вкраїні буде панувать?
Розривають груди її сестри руки,*  |
Убивають душу - а сини мовчать.    |(x2)

Нащо ж діди наші з ляхом воювали
І навіщо Гонта убивав синів? -
Правнуки Богдану коня осідлали -   |
Виїхав на площу і закам''янів.      |(x2)

Навкруг Чигирину по степу кургани -
Там могила скіфа, слава козакам,
Вони пам''ятають червоні жупани,    |
Чули голос Гонти і Залізняка.      |(x2)','["pisni.org.ua", "cat:istorychni", "cat:suspilno-politychni", "Історичні пісні", "Суспільно-політичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_126101'), datetime('now')),datetime('now'));
