INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1265220','Новорічна','Музика: Павло Доскоч Слова: Павло Доскоч. Виконує: Павло Доскоч','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Вже який рік Новий рік
Разом з тобою стрічаєм,
Так повелося, що ми
Свято це завжди чекаєм.
Будуть пісні і вино,
Стіл у святковій ряднині,
І снігурі за вікном
На молодій горобині.

Приспів:
Біло, кругом, кохана,
Сніжно біло,
До тебе лину через срібло,
Що знов насипала зима.
Снігом, так закружляло
Тихо снігом,
Десь завірюха сумним лісом
Торішне листя заміта...

Світло гірлянди в вікні,
Тиша святкова ледь мліє,
Хоч за вікном снігурі,
Погляд твій душу зігріє.
Келих іскриться вином,
Ніч навіва колискову,
Рік Новий білим крилом
Щось наворожить нам знову.

Приспів.','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1265220'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1265220','Новорічна','Вже який рік Новий рік
Разом з тобою стрічаєм,
Так повелося, що ми
Свято це завжди чекаєм.
Будуть пісні і вино,
Стіл у святковій ряднині,
І снігурі за вікном
На молодій горобині.

Приспів:
Біло, кругом, кохана,
Сніжно біло,
До тебе лину через срібло,
Що знов насипала зима.
Снігом, так закружляло
Тихо снігом,
Десь завірюха сумним лісом
Торішне листя заміта...

Світло гірлянди в вікні,
Тиша святкова ледь мліє,
Хоч за вікном снігурі,
Погляд твій душу зігріє.
Келих іскриться вином,
Ніч навіва колискову,
Рік Новий білим крилом
Щось наворожить нам знову.

Приспів.');
