INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1263725','При долині кущ калини','Українська народна пісня. Виконує: Роман Николів','uk','ukraine_before_1917',NULL,NULL,NULL,'Варіант в стилі Денс- аранжування зроблено на студії - romastudio.','При долині кущ калини
Нахилився до води
(Нахилився до води),
Ти скажи мені, калино,
Як попала ти сюди
(Як попала ти сюди)?..
Ти скажи мені, калино,
Як попала ти сюди?..

Якось ранньою весною
Хлопець бравий прискакав
(Хлопець бравий прискакав),
Милувався довго мною,
А тоді з собою взяв,
(А тоді з собою взяв),
Милувався довго мною,
А тоді з собою взяв.

Він хотів мене калину
Посадить в своїм саду,
(Посадить в своїм саду),
Не довіз і в полі кинув,
Думав, що я пропаду,
(Думав, що я пропаду),
Не довіз і в полі кинув,
Думав, що я пропаду...

Я за землю ухопилась,
Стала на ноги свої,
(Стала на ноги свої),
I навіки залишилась,
Де весна і солов''ї,
(Де весна і солов''ї),
I навіки залишилась,
Де весна і солов''ї','["pisni.org.ua", "cat:narodni", "Народні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1263725'), datetime('now')),datetime('now'));
