INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1265808','Місце є дороге','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'http://vk.com/page-14339992_38740937','Виконують Брати Давидюки (США).','Місце є дороге, де бажав би бути ще,
Там з моїми братами в селі,
Як колись я там жив, Господеві я служив
Там з моїми братами в селі.

Приспів:
О, як радують думки
Про минулі ті роки!
О, як хочеться мені
Бути в Церкві з братами в селі

Як я був молодий, радувався я тоді,
Там з моїми братами в селі,
Де Спаситель благий по любові Своїй
Спас мене там в тій церкві в селі.

Приспів.

Ой, якби в наші дні так молилися б усі,
Як молились в тій церкві в селі.
Треба серце відкрить, а Господь благословить,
Як благословив тоді на селі.

Приспів.','["pisni.org.ua", "cat:christian", "Пісні на християнську тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1265808'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1265808','Місце є дороге','Місце є дороге, де бажав би бути ще,
Там з моїми братами в селі,
Як колись я там жив, Господеві я служив
