INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1264606','Біжать у Почаїв стежки і дороги','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'http://wfucu.org.ua/wp-content/uploads/2012/07/%D1%81%D0%BF%D1%96%D0%B2%D0%B0%D0%BD%D0%B8%D0%BA.pdf','Пісню виконує Чернечий хор Почаївської Лаври.','Біжать у Почаїв стежки і дороги,
Там Божії дзвони гудуть,
До нашого Бога, єдиного Бога
Народи, як води пливуть.

О, Матінко Божа,
До тебе прийшли ми
Напитись святої води.

До нашого Бога, єдиного Бога
Веди нас до нього, веди!

З гаїв солов''їних принесли тобі ми
Букети живих квіточок,
Ми просимо Бога, єдиного Бога
За наших малих діточок.

Ми хочем, щоб діти навчились любити,
Щоб чули вони Божий дзвін.
Ми просимо Бога, єдиного Бога
За наших дочок і синів.

Благаєм за поле, благаєм за море,
Благаєм за села й міста,
Ми просимо Бога, єдиного Бога,
Без нього не квітне життя.

О, Матінко Зоре, втопи наше горе
У хвилях Святої води.
Ми просимо Бога, єдиного Бога
Від нині на вічні віки!','["pisni.org.ua", "cat:christian", "Пісні на християнську тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1264606'), datetime('now')),datetime('now'));
