INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1264303','Незалежність','Музика: Гурт "Океан Ельзи" Слова: Святослав Вакарчук. Виконує: Гурт "Океан Ельзи"','uk','ukraine_1991',NULL,NULL,'аудіозапис','Ringo куплет: соль- мажор (G), ре-мажор (D), ми- минор (E), до -мажор (C), соль -мажор (G) и снова до-мажор (C) - соль- мажор (G) припев: соль-мажор (G), Н7, ми-минор (E), ре-мажор (D), соль-мажор (G), F (фа-мажор баре на втором ладу) и Н7','Одна в моїй кімнаті,
Нема куди тікати...
І їй, напевно, не поможуть
Навіть танки і гармати -
Моя маленька незалежність...
Вона втрачає сили,
У неї зводить крила.
Вона, мов Жана Д''Арк,
Але так по кіношному красива -
Моя субтильна незалежність...

Приспів:
А ти лежиш,
Віддавши всю себе!
Злітаєш до небес,
Зі мною до небес!..

Вона була зі мною,
Надійною сестрою,
Та взяла й зрадила мене,
Бо, познайомивши із тобою,
Сама сховалась у любові.
І от я тут без тями,
Її немає з нами,
Ти випила її усю
Своїми жадними губами -
Мою маленьку незалежність...

I тут лежиш,
Віддавши всю себе!
Злітаєш до небес,
Зі мною до небес!..

Приспів','["pisni.org.ua", "cat:philosophic", "Філософські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1264303'), datetime('now')),datetime('now'));
