INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_12725','Родина','Музика: Олександр Злотник Слова: Вадим Крищенко. Виконує: Назарій Яремчук, Павло Мрежук, Василь Білоцерківський','uk','ukraine_1991',NULL,NULL,'1. Аудіо-альбом "Назарій Яремчук. "Я повернуся" (диск 1)". 2. http://www.yaremchuk.cv.ua/texts_ua.html','Акорди підібрано на слух з аудіо-джерела, спрощено. * Тут при повторі за третім разом є зміна тональності на півтон вгору, останній рядок співається двічі. За другим і третім повтором приспіву останній акорд H7 відсутній.','Вступ: Am Em H7 Em
Може в житті хтось принаду підкине
У чарівничих, звабливих очах.
Тільки родина, як зірка єдина,
Твій порятунок - надійний причал.
Ні, не шукай в своїм серці причину,
Якщо зневіра тебе обпече...
Тільки родина у прикру годину
Схилить надію тобі на плече.
Приспів:
Родина, родина - від батька до сина
Від матері доні добро передам.
Родина, родина це вся Україна
З глибоким корінням, з високим гіллям
В морі спокуси є хвилі великі,
Та не забудь у захопленні ти,
Що лиш родина - бальзамові ліки,
Ліки від старості і самоти
Все відцвітає, і жовкне, і гине,
Вітром розноситься, ніби сміття...
Тільки родина як вічна зернина
На невмирущому полі життя.
Приспів. (x3) *','["pisni.org.ua", "cat:pro-batkiv", "Пісні про любов до батьків"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_12725'), datetime('now')),datetime('now'));
