INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_126707','Мені потрібно','(Кредо). Музика: Олександр Смик Слова: Олександр Смик','uk','ukraine_1991',NULL,'2001','Твоя пісня. Пісенник для молоді. Випуск 3 / Упорядник О. В. Комісаров.- Київ: Музична Україна, 1990','Запис та гармонізація: О. Комісаров. Дещо інший варіант цієї пісні є на аудіо-CD "Олександр Смик. Мистецький проект "Червоне... Чорне... Біле..." (Історія закутків української душі). Ч.1. Мелодії та тексти Олександра Смика." (2001).','С#m                    G#
Мені потрібно зовсім небагато:
Щоб кожне слово западало в серце,
Щоб хлопці не кидались хлібом черствим,
Щоб не забули вишивки дівчата,
Щоб не забули вишивки дівчата.
Щоб мати не кидала немовляти,
Щоб кожен батько не цурався сина.
І ще, щоб просто не стріляли в впину,
Коли стоїш обличчям до багаття.  (x2)
Мені потрібно зовсім небагато:
Щоб не ховали камінь за сорочку,
Додолу щоб не опускали очі,
Коли опівночі пускаєш в свою хату.  (x2)
Щоб Батьківщину вміли відстояти,
Щоб кожен доживав до свого віку,
Щоб до зірок ніколи ми не звикли,-
Мені потрібно зовсім небагато.  (x2)','["pisni.org.ua", "cat:bardivski", "cat:suspilno-politychni", "Бардівські пісні", "Суспільно-політичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_126707'), datetime('now')),datetime('now'));
