INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1271220','Під вишнею дівчина смутна','Українська народна пісня. Виконує: Рушничок','uk','ukraine_before_1917',NULL,NULL,'http://vk.com/topic-19373493_27905095',NULL,'Під вишнею дівчина смутна
