INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1272404','Пісня про літо',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Заспівай мені пісеньку, літо,
Про маленьких пташок і звірят.
