INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1274220','Пісня для молодят','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Сьогодні ви життя з''єднали,
З''єднали руки і серця,
І на поріг сімейний стали,
Щоб разом йти у майбуття!
Тому дозвольте привітати
З єднанням в вашому житті,
Здоров''я, щастя побажати,
Щоб завжди були молоді!

Приспів:
Щоби розлуки ви не знали,
Лише в коханні ви живіть,
А все життя пісні співали
І в парі проживіть зі сто літ!

Нехай вас Бог благословляє,
Батьківські щирії слова,
Нехай вас горе обминає
І доля буде золота!
Щоб в мирі й злагоді прожити,
Не знали горя і біди,
Дітей щасливими зростити,
Онуки й правнуки були!

Приспів.    Фонограма-мінус','["pisni.org.ua", "cat:vesilni", "Весільні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1274220'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1274220','Пісня для молодят','Сьогодні ви життя з''єднали,
З''єднали руки і серця,
І на поріг сімейний стали,
Щоб разом йти у майбуття!
Тому дозвольте привітати
З єднанням в вашому житті,
Здоров''я, щастя побажати,
Щоб завжди були молоді!

Приспів:
Щоби розлуки ви не знали,
Лише в коханні ви живіть,
А все життя пісні співали
І в парі проживіть зі сто літ!

Нехай вас Бог благословляє,
Батьківські щирії слова,
Нехай вас горе обминає
І доля буде золота!
Щоб в мирі й злагоді прожити,
Не знали горя і біди,
Дітей щасливими зростити,
Онуки й правнуки були!

Приспів.    Фонограма-мінус');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_1274220_l1','pisniua_1274220','http://minus.lviv.ua/','http://minus.lviv.ua/','external',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1269127','Закохалась я на весні','(Закохалася дівчина). Музика: Володимир Пацула Слова: Володимир Пацула, MVM. Виконує: Микола Веремко, Віталій Скорвінок','uk','ukraine_1991',NULL,NULL,NULL,'*в оригіналі пісня - 1,2 строфа і приспів, 3-5 строфи дописані','Закохалася дівчина
У хлопчину на весні
Та не знала та дівчина,
Що не любить він її.

Приспів:
Закохалась я на весні
Та й не знала, що уві сні
Назбирала квітів рясних
І сказала йому "НІ".

На побачення хлопчина
До дівчини не прийшов,
Вона так його чекала,
Хоч і дрібний дощ ішов.

Приспів.

Довго думала дівчина,
Ну чому ж він не прийшов
І не знала та дівчина,
Що він іншу вже знайшов.

Приспів.

Поспішала знов дівчина,
Обіцяв їй, що прийде,
Та не знав отой хлопчина,
Що дитина вже росте.

Приспів.

Так чекала, так чекала
Та він знову не прийшов
І з дівчиною й з дитятком
Поїзд в синю даль ішов.

Приспів','["pisni.org.ua", "cat:halycki", "Пісні з Галичини"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1269127'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1269127','Закохалась я на весні','Закохалася дівчина
