INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1273921','Цей Новий Рік!','Музика: Степан Вовкун Слова: Степан Вовкун. Виконує: Степан Вовкун','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Цей Новий Рік
Хай буде кращим ніж той рік!
Живи, радій
І посміхайся цілий рік!

Життя прекрасне...
Хоч ми жаліємось на нього.
Все буде класно...
Ти тільки вір і прагни того.
Не озирайся...
Йди вперед і посміхайся
Повір у себе...
Тому, що все залежить лиш від тебе.

Цей Новий Рік
Хай буде кращим ніж той рік!
Усім добра, любові,
Радості й тепла!
Цей Новий Рік
