INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1273303','Бузок','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'За вікном розцвів зелений
Запашний бузок,
Чом до мене не приходиш,
Милий мій дружок?..
Цвіт пахучий, білий,
Де ж ти ходиш, милий,
Жду тебе коханий мій,
Зрозумій.

А я жду його, немає,
Важко так мені,
А бузок вже розцвітає,
Квіти чарівні.
Цвіт пахучий, білий,
Де ж ти ходиш, милий,
Жду тебе коханий мій,
Зрозумій.

Засмутилось моє серце,
Серце молоде,
А бузок мені шепоче:
Він прийде, прийде...
Цвіт пахучий, білий,
Де ж ти ходиш, милий,
Жду тебе коханий мій,
Зрозумій.','["pisni.org.ua", "cat:nostalgia", "Пісні з ностальгічними мотивами"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1273303'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1273303','Бузок','За вікном розцвів зелений
