INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_127622','Ой у лісі, на поляні старий батько воли пас','Виконує: Володимир Вермінський','uk','ukr_ssr_1919_1991',NULL,NULL,'CD "Йшли селом партизани" (с) 2002 ПТ "GroLis Records" (м. Тернопіль), http://www.grolis.com.ua',NULL,'Ой у лісі, на поляні старий батько воли пас,
По дорозі пробирався партизанський відділ наш. | (2)

По дорозі йде підвода, а на ній червоний хрест,
А з підводи чути голос: "Скоро буде мій кінець".

Санітарка там сиділа, їй на серці тяженько.
Її мужа розстріляли, серце кров''ю облилось.    | (2)

Один просить, напишіть вже до моєї родини,
Другий просить, напишіть вже до моєї дівчини.

Вона пиши, він диктує: "Як ся маєш, дорога?
Я на фронті, легко ранен, скоро дома буду я".  | (2)

І промовив тихе слово, повернувся легенько,
Відхиливши праву руку, душа вийшла із його.

Ой у лісі, на поляні старий батько воли пас,
По дорозі пробирався партизанський відділ наш. | (2)','["pisni.org.ua", "cat:istorychni", "cat:povstanski", "Історичні пісні", "Повстанські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_127622'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_127622','Ой у лісі, на поляні старий батько воли пас','Ой у лісі, на поляні старий батько воли пас,
По дорозі пробирався партизанський відділ наш. | (2)

