INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1278426','Іди!','Слова: Сергій Цушко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Гаранте! Ти казав, що всіх почуєш.
Що ж нині, як наперсточник, блефуєш?
Що ж мурами себе відгородив?..
Якщо глухий - іди собі! Іди!

Ти обіцяв, що про народ подбаєш,
То що ж під себе все підряд згрібаєш,
На унітазі золотім сидиш?
Якщо крадій - іди собі! Іди!

Ти богомільним числишся без міри.
Які ж засади у твоєї віри?
Твій бог - московський кадебіст рудий.
Молись йому - іди собі! Іди!

Повстала нині гнівно вся країна,
Яка не хоче стати на коліна.
Щоб не було ще більшої біди -
Пощезни геть! Іди собі! Іди!

Вже пізно говорити й прислухатись,
За "беркутами" й мурами ховатись.
Банкроте політичний, не смерди -
Під улюлюкання іди собі! Іди!','["pisni.org.ua", "cat:euromaydan", "Пісні Євромайдану"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1278426'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1278426','Іди!','Гаранте! Ти казав, що всіх почуєш.
Що ж нині, як наперсточник, блефуєш?
Що ж мурами себе відгородив?..
Якщо глухий - іди собі! Іди!

Ти обіцяв, що про народ подбаєш,
То що ж під себе все підряд згрібаєш,
На унітазі золотім сидиш?
Якщо крадій - іди собі! Іди!

Ти богомільним числишся без міри.
Які ж засади у твоєї віри?
Твій бог - московський кадебіст рудий.
Молись йому - іди собі! Іди!

Повстала нині гнівно вся країна,
Яка не хоче стати на коліна.
Щоб не було ще більшої біди -
Пощезни геть! Іди собі! Іди!

Вже пізно говорити й прислухатись,
За "беркутами" й мурами ховатись.
Банкроте політичний, не смерди -
Під улюлюкання іди собі! Іди!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1280505','Ой, єсть в лісі калина','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Ой, єсть в лісі калина,  | (2)
Калина-калина,
Комарики-дзюбрики, калина.
Калина-калина,
