INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_128808','Ой у саду ружа посаджена','Українська народна пісня. Виконує: Юлія Дошна, Бурдон','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Ой у саду ружа посаджена,
Каже хлопець, же я не червена.
Та най каже, а я не журюся,
Кому мила, тому сподоблюся.

Не кладу на личко червенило,
Мене в поли сонце припалило,
Припалило спереду і збоку,
А я собі дівчина нівроку.

Мене мати в плахті колихала,
При кирниці кождий день купала.
Ой купала та й забула втерти,
Буду файна до самої смерти.','["pisni.org.ua", "cat:lemkivski", "Лемківські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_128808'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_128808','Ой у саду ружа посаджена','Ой у саду ружа посаджена,
Каже хлопець, же я не червена.
Та най каже, а я не журюся,
Кому мила, тому сподоблюся.

Не кладу на личко червенило,
Мене в поли сонце припалило,
Припалило спереду і збоку,
А я собі дівчина нівроку.

Мене мати в плахті колихала,
При кирниці кождий день купала.
Ой купала та й забула втерти,
Буду файна до самої смерти.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_128808_l1','pisniua_128808','YouTube','https://www.youtube.com/watch?v=b80aJmvtqs8','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1287725','Злива','(Лий, зливо, лий!). Музика: Дмитро Шуров Слова: Андрій Хливнюк. Виконує: Джамала, Андрій Хливнюк','uk','ukraine_1991',NULL,NULL,'аудіозапис','Підбір акордів Oleg_XXX.','З неба знову вода,
Всі ми з нею один на один,
Хтось благає: до мене йди,
А комусь вже підмило тин.
Dm#  Dm#/D
З неба знову вода, вода,
Dm#/C#          Dm#/C
Дощ її нам на двох налив,
Bm
Щойно була весна, а вже осінь руда,
Рік пройшов, мов водою всіх нас вмив...
Що змінилось, лишилось що,
Чи заради цього так мерзли всі?
Є рука у моїй руці,
Є мета, щоб були разом руки ці.
Скільки нас, тих хто прагне див?..
Кожен третій, чи може всі?
Після зливи на ранок один на всіх
Може матиме те, що не мали досі.
Приспів:
Bm
Лий, зливо, лий!
Відмивай нас всіх від бруду,
Dm#
Літній дощ...
Ми втомились як ніколи від зими,
Лий, зливо, лий
Я навряд чи буду тим, ким я була,
Одного прошу травневих злив:
Най би дощ пішов
І зиму змив, і зиму змив...
З неба знову вода, вода,
Всі ми з нею один на один,
Скляноокий брехливий звір
Розколов мільйон родин,
Що змінилось, лишилось що?..
Від новин підірвало дах,
Брат на брата - найбільший жах,
Ті брати тепер - я і ти,
Не існує ніяких "Їх",
Ця земля нами зорана,
Хочеш крові моє - на!
В нас червона обох вона,
Тож не несіть нам у дім біди
Всі в воду йдем і вийшли з води,
Але не змити з пам''яті ні один із тих,
Хто буде молодим тепер назавжди.
Приспів.
А я раніше дощ, дощ не любив - лий!
Мокрий і бридкий, гострий такий - лий!
Малим не був байдужо до калюж,
А так терпів, чекав аби скоріше пройшов,
І сонце знов, і дах сухий.
Але сьогодні дощ не такий, чи я не такий,
То лий, лий, лий, лий!
Як червоніє бачили сніг - лий!
Як люди пригортають людей моїх,
Я так пишаюсь вами і так боюсь,
Що знов побачу, як нацькують
Розкажуть, що комусь вороги - лий!
І той повірить у ці жахи, жахи -
Лий, лий!..
Приспів. (2)
Лий, зливо, лий...
Лий, зливо, лий..','["pisni.org.ua", "cat:euromaydan", "Пісні Євромайдану"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1287725'), datetime('now')),datetime('now'));
