INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_1282622_l1','pisniua_1282622','YouTube','https://www.youtube.com/watch?v=FGZl9jobgxE','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1281404','Осіння пісня','Музика: Наталія Май Слова: Наталія Май. Виконує: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Заблукало літо у полях,
Розгубило в травах роси.
Заблукало літо у житах
І зустріло тиху осінь.

Приспів:
Осінь, осінь золотава,
Ти - утіха для душі.
Осінь, осінь, будь ласкава,
Відлітати не спіши.

І співало літо, наче птах,
І гойдало вербам віти,
І ходило літо по стежках,
Щоб осінь там зустріти.

Приспів. (2)','["pisni.org.ua", "cat:krasa-pryrody", "Пісні про красу природи"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1281404'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1281404','Осіння пісня','Заблукало літо у полях,
Розгубило в травах роси.
Заблукало літо у житах
І зустріло тиху осінь.

Приспів:
Осінь, осінь золотава,
Ти - утіха для душі.
Осінь, осінь, будь ласкава,
Відлітати не спіши.

І співало літо, наче птах,
І гойдало вербам віти,
І ходило літо по стежках,
Щоб осінь там зустріти.

Приспів. (2)');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1282909','Поминальна','Слова: Ольга Покришка','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Вселенська скорбота тремтить над Майданом,
В руках поминальна палає свіча...
А в душах ятрить незагоєна рана...
У ряд домовини несуть на плечах...

Несуть козаків... У розриту могилу
Навіки ховають обірваний Цвіт...
І уст не цілованих усміх застиглий
Жалем невимовним наповнює світ...

У небі дзвенить недоспівана пісня,
Летить ластів''ям ненароджений син...
Роситься сльозою розстріляна мрія...
І хтось не дожив до своїх уродин...

Татусь не зведе на подвір''ї криниці,
Не зможе калину дочці посадить...
А хтось не засіє із сином пшениці
І хлібом до шлюбу не благословить...

А десь у саду вже не виросте вишня...
А десь у дворі не довершений дім...
І десь під хатиною лава порожня -
Там більше не сяде з онуками дід.

Десь тужить-ридає вдова-наречена,
Сльозами вмиває весільний рушник...
У чорній хустині матуся старенька
Гамує у серці затаєний крик...

На свіжій могилі тюльпани розквітли
І тихо горить поминальна свіча...
Молитва задушна лине над світом:
"На Вічную Пам''ять, на Вічне Життя..."','["pisni.org.ua", "cat:euromaydan", "Пісні Євромайдану"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1282909'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1282909','Поминальна','Вселенська скорбота тремтить над Майданом,
В руках поминальна палає свіча...
