INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_1288921_l1','pisniua_1288921','YouTube','https://www.youtube.com/watch?v=wJi37XJVB_U','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1281725','Зайшло сонечко','Музика: Ніна Матвієнко Слова: Ніна Матвієнко. Виконує: Ніна Матвієнко','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Зайшло сонечко,
Стало темно,
Ніч підкралася
На лапочках.
Івасику пора
Вже спать.
А він сердиться,
Крутить носиком,
І став легенько
Схлипувать.

Івасику,
Голубчику,
Чого не спиш,
Синочку мій?
І горобчик спить,
І котик спить,
І тільки ти не спиш.','["pisni.org.ua", "cat:kolyskovi", "Колискові"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1281725'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1281725','Зайшло сонечко','Зайшло сонечко,
