INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1287404','Стрільці галичанського краю','Музика: Іван Миськів Слова: Богдан Тихий','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'інтернет','1 Геннадій Мороз 2 Андрій Чайковський 3 Мирослав Кушнір 4 Маркіян Шашкевич','На Лисоні калина зітхає,
Плаче вітер у зворах горбів,
Йдугь стрільці Галичанського краю,
Щоб не бути у стані рабів.

Приспів:
Богдане, Богдане, твої Бережани
Летять журавлем у вирій.
Моя Україно — земля солов''їна,
Ти раю земного прибій.

Йде Олена Кульчицька з Морозом1,
Йдуть Андрій2, Мирослав3, Маркіян4.
Йдуть крізь долі буремні і грози
Лепкі з ними — Левко та Богдан.

Приспів.

Це крокують мої Бережани,
Їхня слава дзвінка і проста.
I клубочаться сиві тумани
Там, де Липа шумить Золота.

Приспів.','["pisni.org.ua", "cat:strilecki", "Стрілецькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1287404'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1287404','Стрільці галичанського краю','На Лисоні калина зітхає,
