INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1289529','Жартівлива колядочка','Слова: Л. Пінчук','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Я колядник хоч куди,
В мене гарні чобітки.
Маю теплий кожушок
Та порожній ще мішок!

Ось я вам заколядую!
Слів для вас не пошкодую!
Ну, а ви ж мені на свято
Накривайте стіл багато:

Шмат ковбаски, сиру трішки,
Можна яблука й горішки,
Тортик "Празький" солоденький,
Ще й цукерочок дві жменьки!

Я ж бажаю всій родині
Дні яскраві, теплі, мирні!
Хай Господь дарує радо
Вам в сім''ю "Тойоту Прадо"!

Щоб завжди були у парі,
Побажаю ще й "Ферарі",
Замок в Австрії та Римі,
Де басейнів аж чотири.

До смачненького слівця
Побажаю шмат сальця!
Діамантів ще бажаю
Та мішечок наставляю!','["pisni.org.ua", "cat:dytyachi", "Дитячі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1289529'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1289529','Жартівлива колядочка','Я колядник хоч куди,
