INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_129404','Коли хмеліє в думках голова','(Про неї). Музика: Ярослав Юрчишин Слова: Ярослав Юрчишин. Виконує: Ярослав Юрчишин','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Коли хмеліє в думках голова
Не забувай, щаслювцю, миті цеї
Тоді у ній народяться слова
До неї однієї.

Коли у ватрі холод дотліва
І ніжно хилять голови лілеї
Навічно викарбуються слова
До неї однієї

Коли втікаєш з потягу життя
Який посіли блазні і лакеї
Не згадуй надаремо ти ім''я
Тікаючи не варто й думати про неї.

А час минає. Більше вороття
Назад не буде. Бриз цілує реї.
Реальні на планеті почуття
Все решта - тлін. Крім неї однієї','["pisni.org.ua", "cat:bardivski", "Бардівські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_129404'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_129404','Коли хмеліє в думках голова','Коли хмеліє в думках голова
Не забувай, щаслювцю, миті цеї
Тоді у ній народяться слова
До неї однієї.

Коли у ватрі холод дотліва
І ніжно хилять голови лілеї
Навічно викарбуються слова
До неї однієї

Коли втікаєш з потягу життя
Який посіли блазні і лакеї
Не згадуй надаремо ти ім''я
Тікаючи не варто й думати про неї.

А час минає. Більше вороття
Назад не буде. Бриз цілує реї.
Реальні на планеті почуття
Все решта - тлін. Крім неї однієї');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_129426','Ой був у Січі Старий Козак на прізвище Чалий','Українська народна пісня. Виконує: Микола Будник','uk','ukraine_before_1917',NULL,NULL,'Співає зі старосвітською бандурою кобзар Микола Будник: Воскресні та Спасительні пісні © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2003','Спасительна: світ не по Правді. Українські релігійні роздуми про Воскресіння, Неволю і Спасіння. Ой Ми зіслані на признаванє. Нема в світі Правди не зіскати. Ускочили Три Козаки тай стали питати. А чи ж нам Панове Лицарі ой не ганьба тепера. Листки з приводу цієї Пісні: Українські реліґійні роздуми про Неволю та Спасіння Коляда і Великдень: Різдво і Відродження Світа. Бог, Різдво Світа, Прадід і Лицарі. Стежки до листків про Українські традиції.','Ой був у Січі Старий Козак на прізвище Чалий
Він згодував сина Саву Козакам на славу...

Не схотів же да той Сава Козакам служити
Відклонився до ляшеньків паном в Польщі жити...

Відклонився до ляшеньків паном у Польщі жити
А Козаків-Запоріжців по степах ловити...

Відклонився до ляшеньків паном у Польщі жити
А нарід наш християнський у неволеньку продати...

Став же Сава у Потоцьких дворовим сотником служити
Да вірненько самим Потоцьким службу дворовую правити...

Став же на гарді козацькому гарди гей розбивати
Церковичку і школу із вогнем пускати...

А Наш Батько Пан Кошовий на ті тяжкії трати тужить
Ой хто піймає сина Саву сам тому послужу...

Гей ви Гнатко із Кравчиною славнії лицарі
Ви ж колись у кума у пана Сави ой перебували...

А чи ж нам Панове Лицарі ой не ганьба тепера
Що кум ваш чинить на Вкраїні тяжкий розбій гей...

Ой якщо ж ви пана Сави у свої рученьки не возьмете
Свої голівоньки отут на Святій Січі гей покладете гей...

По дорозі їм зустрівся Литвин тай став наставляти
Як їм того пана Саву у свої рученьки взяти...

Насипайте каже землі рідної у чоботи під ноги
Щоб не знати вам Панове Побратими вражої підмови...

Сидить Сава у світлиці дрібно листи пише
А Савиха молодая Дитину колише...

А стомившись писати листи одпочити ляже
А хтось йому під віконцем Добрий Вечір каже...

А скінчивши писати листи каже своєму Джурі
Піди-но Хлопче піди-но Малий да уточи-но пива...

Піди-но Хлопче піди-но Малий да уточи-но Пива
А ми вип''ємо з моєю Жінкою за здоровлє Сина...

Піди-но Хлопче піди-но Малий да уточи нам Горілки
А ми вип''ємо із Тобою за здоровлє Жінки...

Ой піди-но Хлопче піди-но Малий да уточи нам Меду
Бо щось мені тяжко-важко голови не зведу...

Не вспів Хлопець не вспів Малий увійти у пивницю
Ускочили Гайдамаки до Сави в світлицю...

Як кинецця да пан Сава до Ясної Зброї
А Гнат Голий йому каже це тобі не в Полі...

Як кинецця да пан Сава до Гострого Меча
Одлетіла голівонька із Савиного плеча...

Оце тобі пане Саво сукні-адамашки
Що ти нажив вражий сину із панської ласки...

Оце тобі пане Саво Церковички Святії руйнувати
Оце тобі пане Саво Школи наші закривати...

Оце тобі пане Саво ой нарід наш християнський
православний у рабство продавати
Оце тобі пане Саво ой свої козацькії звичаї
і славнії лицарськії традиції гей забувати гей','["pisni.org.ua", "cat:dumy", "cat:istorychni", "cat:kozacki", "cat:philosophic", "cat:suspilno-politychni", "Думи", "Історичні пісні", "Козацькі пісні", "Філософські пісні", "Суспільно-політичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_129426'), datetime('now')),datetime('now'));
