INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_1294606_l1','pisniua_1294606','YouTube','https://www.youtube.com/watch?v=Eu7NDJpbTsg','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1288909','Гімн українській мові','Музика: Крайня Хата Слова: Крайня Хата. Виконує: Крайня Хата','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Так багато різних мов існує в світі,
Знають добре навіть це маленькі діти.
Кожна кращою є для свого народу,
Богом українська дана в нагороду!

Всім гостям ми раді, хто повагу має,
До традицій наших й мову хто вивчає.
Тим, кому до українського байдуже,
Ми не подамо руки з тобою, друже!

Стань поруч і заспіваймо, брате,
Мову батьківську всім треба знати.
Мову держави, в якій живемо,
Прапор якої у світ несемо!

Хто б ти не був і якої віри,
Насамперед ти є українець!
Тож гідним будь України-неньки,
Мову козацьку люби серденьком!

Ти не будь в своїй державі яничаром,
Що несе Вкраїні лихо і покару.
Мову продає, що від дідів зосталась,
Віру віддає чужинцям на поталу.

Але станем ми пліч-о-пліч проти змови,
Занедбати не дамо своєї мови!
Всі ми патріоти неньки України,
В нас вона одна і мова в нас єдина!','["pisni.org.ua", "cat:himny-marshi", "cat:patriotic", "Гимни та марші", "Патріотичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1288909'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1288909','Гімн українській мові','Так багато різних мов існує в світі,
Знають добре навіть це маленькі діти.
Кожна кращою є для свого народу,
Богом українська дана в нагороду!

Всім гостям ми раді, хто повагу має,
До традицій наших й мову хто вивчає.
Тим, кому до українського байдуже,
Ми не подамо руки з тобою, друже!

Стань поруч і заспіваймо, брате,
Мову батьківську всім треба знати.
Мову держави, в якій живемо,
Прапор якої у світ несемо!

Хто б ти не був і якої віри,
Насамперед ти є українець!
Тож гідним будь України-неньки,
Мову козацьку люби серденьком!

Ти не будь в своїй державі яничаром,
Що несе Вкраїні лихо і покару.
Мову продає, що від дідів зосталась,
Віру віддає чужинцям на поталу.

Але станем ми пліч-о-пліч проти змови,
Занедбати не дамо своєї мови!
Всі ми патріоти неньки України,
В нас вона одна і мова в нас єдина!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_130000','Ой як то було з Початку Світа','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Колядка стародавня: Українське Різдво Світа (Коляда). Ой но на Морі Павутиноньки. Заснування Світа. Первовічна Павутинонька. Світотворча Астральна Трійця. Коли не било з Нащада Світа Коли не було з Нащада Світа Колись то було з Початку Світа Ой грало Море в Неділю рано Ой як то було з Початку Світа Ой як то було з Початку Світа Боже Наш Ой як то ще було із Нащада Світа Сіяти Павучки-павучки. До Саду Дівчата до Саду Ой Білая Паутина Ой Снодо Снодо Тонкая Там Біленьке Павутиння Листки з приводу цієї Пісні: Українські релігійні роздуми про Бога. Колядки про Почин Світа. Українське Свято Воведення 4.12 - Передріздвяний Святочний час. Стежки до листків про Українські традиції. Первовічна Павутинка. Про зовсім відмінне світотворче і мітольоґійне становище Колядки "Ой як то було з Початку Світа", серед усіх Колядок про Почин Світа і про велику пракультурність світогляду в ній висловленого, була бесіда в попереднім розділі. Така космоґонійна ідея, щоб Місяць, Сонце і Дощик були Творцями Світа, є мабуть одинока між космоґонійними традиціями світа. Дуже збентежуюче в цій Колядці є це, що Місяць, Сонце і Дощик появилися в Первовіці на Павутиноньці над Морем. Є в цім безперечна подібність образів до переказу мендулянських Каянів з острова Борнео — про гніздо з павутини, в яке упав з неба каміньчик (перлина), що з нього відтак сталася земля. Була вже мова про це, що той мітичний каміньчик і гніздо павука — це символ Місяця. Але в Українській Колядці Астральні світила на Павутині називаються виразно по імені, і в товаристві Дощику творять своєрідну Українську Небесну Трійцю — і такого повного мітольоґійного образця, ні відокремленого, ні в злуці з мітичною Павутиною, в Австронезьких областях нема. Що бачення першої речовинної видимої появи в Почині Світа — в подобі Павутини — не є припадковим в Українському світогляді, але засвоєним, може й автохтонним, свідчить друга Колядка "Ой як то було з Початку Світа Боже Наш", яка теж про Первовічну Павутинку говорить. Див. "Ой як то ще було із Нащада Світа" Свідчить також мова Колядки "Коли не било з Нащада Світа", в якій Голуби радяться як Світ сновати. Цей вислів "сновати" відноситься первісно лиш до роботи павука, снуючого своє гніздо. Див. Коли не било з Нащада Світа Коли не було з Нащада Світа Колись то було з Початку Світа Ой грало Море в Неділю рано Ой як то ще було із Нащада Світа Міт Мендулян Каянів, о. Борнео. Мітичного світотворчого Птаха в цім міті заступає Павук. Колись спустився павук з неба на павутині і заснував гніздо, в яке упав каміньчик, завбільшки перлини. (Порівняння вказує, що камінчик блестів, світився. Це мотив Астральний.) Він розростався помалу так, що зайняв уесь простір під небом. Ця перлина зростала чотирма фазами ось як: 1) добірною перлою, ower ane; 2) маленькою мушлею (kentobong аро halo); 3) нігтиком (halo, der Nagel) серповидної або півокруглої подоби — Місячний образ; 4) шибкою, вирізаною з мушлі, тарілкою, подібною до кружковатої мати до сідання, або сита (barang halo). На цей камінь впала з неба корина (луска, Flechte) й прилипла до нього; відтак упав хробак, а з його калу сталися перші дрібки землі, яка розрослася велика по всім камені. Тоді впав з неба кусень дерева, яке розрослося відтак як банан; опісля впав з неба краб, що порпався в землі, а з того повстали гори й доли та русла рік. Міт оповідає дальше про появу рослин, дерев та цілих садів, про два людські духи мужа й жінки, що впали з неба, та про їх першу дочку (Lachei Lahan), яка зродила двоє дітей, — первісних людей, — та четверо інших дітей: чотири місячні фази — сходячого Місяця-молодика, Півмісяця, Місяця у повні та заникаючого темніючого Місяця. Інші її діти розбіглися по всесвіті та жиють як Місяці й подібні їм творива. Які важні оці мітольоґійні історії для розсліду Українських, покажеться в розвитку дальших наших дослідів. (За працею: о. Ксенофонт Сосенко. "Культурно-історична постать Староукраїнськиx свят Різдва і Щедрого Вечора". Львів, 1928. - СІНТО, Київ 1994. 343с.) Павуки й Теремки. "Павука", — 12 стрічок, зчеплених прикрас, з почергово з''єднаних соломинок та паперових кружечків, — підвішують до стелі, а під ним чіпляють "Теремок": його "Павутину", — своєрідну просторово-розмірену будівлю з соломи. Пригадати Колядки про Прадерево, між якими замість мотиву космічних Вод стрічається мотив Широкого Поля, або якоїсь таємної сторони, а часом — містичної будівлі, де відбуваються біля Прадерева і за його причиною первовічні події. Потрібно 12 соломин, 8 довгих та 4 трохи коротших, на поперечні смуги, з яких виготовляється щось схоже на об''ємний ромб. До нього підвішуються подібні, але менші появи, прикрашені квітами з кольорового паперу. (Радуйся, Земле, Коляда їде! 2000. Автор-упор. Ярослава Музиченко. Ред., муз.ред. Катерина Міщенко. Худ. Олена Гайдамака. Київ, "Смолоскип" 2000. 152с.) Святоріздвяний світогляд виражається і в народному ставленні до павуків: їх не можна убивати, до них треба ставитися з пошаною як до охоронців. Корені такого ставлення праісторичні. Християнські легенди продовжують давній Український і світовий символізм Місяця, пов''язаний з павуком: про павука, який заснував вхід до печери, де сховалися під час втечі до Єгипту Марія та Ісус; про павука, який замітав сліди Божої Матері з Дитям під час втечі від Іудейського царя Ірода; про павука, який виткав і подарував новонародженому Ісусові сорочку. У зв''язку з Павутинкою цікаво згадати сучасні наукові побудови про квантові збурення первісної "порожнечі", "квантові струни-нитки" та багатовимірні простори. Словничок: Автохтонний, — від гр. "autos" – "сам" і "khthôn" – "земля", — самородний. "Мата", ж., рід товстої рогожі з соломи (словник Грінченка).','Ой як то було з Початку Світа
Як ще не було Неба ні Землі
Ой но на Морі Єдна Павутинка

На тій Павутинці Три Товариші
Єден товариш Ясне Соненько
Другий товариш Ясний Місяченько
Третий товариш Дрібний Дощенько

Чим ся похвалиш Ясне Соненько ?
Ой як я зійду в Неділю рано
Ой як огрію Діти Малії
Діти Малії і Люди Старії

Чим ся похвалиш Ясний Місяченьку ?
Ой освічу я гори-долини
Гори-долини Церкви-й-костьоли
Церкви-й-костьоли Гостя у Дорозі

Чим ся похвалиш Дробний Дощику ?
Ой як я впаду Три Рази в Маю
Ой зрадується Жито-пшениця
Жито-пшениця всяка Ярениця

А за тим Словом бувайте здорові
Здоровля у той Дім на Челядоньку
Щастенько на Двір на Худобоньку','["pisni.org.ua", "cat:shchedrivky", "Щедрівки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_130000'), datetime('now')),datetime('now'));
