INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_129101','Мамина вишня','(Знову наснилось дитинство...). Музика: Анатолій Пашкевич Слова: Дмитро Луценко. Виконує: Раїса Кириченко, Медобори, Любов Камінська','uk','ukraine_1991',NULL,NULL,'1. http://schoolmusic.narod.ru/muzika_8class.html 2. http://ukrlife.org/main/mother/mother_ua6.htm',NULL,'Знову наснилось дитинство,
